#define NS_SANDBOX_ACTIVE              (1u << 0)
#define NS_SANDBOX_ALLOW_SCRIPTS       (1u << 1)
#define NS_SANDBOX_ALLOW_FORMS         (1u << 2)
#define NS_SANDBOX_ALLOW_SAME_ORIGIN   (1u << 3)
#define NS_SANDBOX_ALLOW_POPUPS        (1u << 4)
#define NS_SANDBOX_ALLOW_MODALS        (1u << 5)
#define NS_SANDBOX_ALLOW_TOP_NAV       (1u << 6)
#define NS_SANDBOX_ALLOW_TOP_NAV_UA    (1u << 7)
#define NS_SANDBOX_ALLOW_DOWNLOADS     (1u << 8)
#define NS_SANDBOX_ALLOW_POPUPS_ESCAPE (1u << 9)
#define NS_SANDBOX_ALLOW_POINTER_LOCK  (1u << 10)
#define NS_SANDBOX_ALLOW_PRESENTATION  (1u << 11)
#define NS_SANDBOX_ALLOW_ORIENTATION   (1u << 12)
/* Internal flag, never produced by the sandbox-attribute parser: set when the
   frame is cross-origin to its embedder, to deny it the embedding origin's
   localStorage/sessionStorage/cookies (the runtime's storage is keyed to the
   top origin). Must match the (sandbox & 8192) checks in the realm bootstraps. */
#define NS_FRAME_CROSS_ORIGIN          (1u << 13)

static const struct { const char *token; unsigned flag; } ns_sandbox_tokens[] = {
    { "allow-scripts",                          NS_SANDBOX_ALLOW_SCRIPTS },
    { "allow-forms",                            NS_SANDBOX_ALLOW_FORMS },
    { "allow-same-origin",                      NS_SANDBOX_ALLOW_SAME_ORIGIN },
    { "allow-popups",                           NS_SANDBOX_ALLOW_POPUPS },
    { "allow-modals",                           NS_SANDBOX_ALLOW_MODALS },
    { "allow-top-navigation",                   NS_SANDBOX_ALLOW_TOP_NAV },
    { "allow-top-navigation-by-user-activation", NS_SANDBOX_ALLOW_TOP_NAV_UA },
    { "allow-downloads",                        NS_SANDBOX_ALLOW_DOWNLOADS },
    { "allow-popups-to-escape-sandbox",         NS_SANDBOX_ALLOW_POPUPS_ESCAPE },
    { "allow-pointer-lock",                     NS_SANDBOX_ALLOW_POINTER_LOCK },
    { "allow-presentation",                     NS_SANDBOX_ALLOW_PRESENTATION },
    { "allow-orientation-lock",                 NS_SANDBOX_ALLOW_ORIENTATION },
};

static unsigned
ns_sandbox_parse_tokens(const char *val)
{
    unsigned flags = NS_SANDBOX_ACTIVE;
    if (!val) return flags;
    const char *p = val;
    while (*p) {
        while (*p && g_ascii_isspace((guchar)*p)) p++;
        const char *s = p;
        while (*p && !g_ascii_isspace((guchar)*p)) p++;
        gsize len = (gsize)(p - s);
        if (len == 0) continue;
        for (gsize i = 0; i < G_N_ELEMENTS(ns_sandbox_tokens); i++) {
            const char *t = ns_sandbox_tokens[i].token;
            if (strlen(t) == len && g_ascii_strncasecmp(s, t, len) == 0) {
                flags |= ns_sandbox_tokens[i].flag;
                break;
            }
        }
    }
    return flags;
}

static unsigned
ns_iframe_effective_sandbox(const ns_node *node)
{
    unsigned flags = 0;
    gboolean any = FALSE;
    for (const ns_node *p = node; p; p = p->parent) {
        if (!ns_node_is_element_named(p, "iframe")) continue;
        const char *val = ns_element_get_attr(p, "sandbox");
        if (!val) continue;
        unsigned f = ns_sandbox_parse_tokens(val);
        if (!any) { flags = f; any = TRUE; }
        else flags &= f;
    }
    return any ? (flags | NS_SANDBOX_ACTIVE) : 0;
}

static gboolean
ns_node_sandbox_blocks_forms(const ns_node *node)
{
    unsigned sb = ns_iframe_effective_sandbox(node);
    return (sb & NS_SANDBOX_ACTIVE) && !(sb & NS_SANDBOX_ALLOW_FORMS);
}

static JSValue
ns_mql_initial_notify_job(JSContext *ctx, int argc, JSValueConst *argv)
{
    (void)argc;
    JSValue ev = JS_NewObject(ctx);
    JS_SetPropertyStr(ctx, ev, "type", JS_NewString(ctx, "change"));
    JS_SetPropertyStr(ctx, ev, "matches",
                      JS_GetPropertyStr(ctx, argv[0], "matches"));
    JS_SetPropertyStr(ctx, ev, "media",
                      JS_GetPropertyStr(ctx, argv[0], "media"));
    JSValue r = JS_Call(ctx, argv[1], argv[0], 1, (JSValueConst *)&ev);
    if (JS_IsException(r)) JS_FreeValue(ctx, JS_GetException(ctx));
    JS_FreeValue(ctx, r);
    JS_FreeValue(ctx, ev);
    return JS_UNDEFINED;
}

static JSValue
ns_mql_addListener(JSContext *ctx, JSValueConst this_val,
                   int argc, JSValueConst *argv)
{
    if (argc < 1 || !JS_IsFunction(ctx, argv[0])) return JS_UNDEFINED;
    JSValueConst args[2] = { JS_NewString(ctx, "change"), argv[0] };
    JSValue r = ns_target_addEventListener(ctx, this_val, 2, args);
    JS_FreeValue(ctx, args[0]);
    JSValueConst jargs[2] = { this_val, argv[0] };
    JS_EnqueueJob(ctx, ns_mql_initial_notify_job, 2, jargs);
    return r;
}

static JSValue
ns_mql_addEventListener(JSContext *ctx, JSValueConst this_val,
                        int argc, JSValueConst *argv)
{
    JSValue r = ns_target_addEventListener(ctx, this_val, argc, argv);
    if (argc >= 2 && JS_IsFunction(ctx, argv[1])) {
        const char *type = JS_ToCString(ctx, argv[0]);
        if (type && strcmp(type, "change") == 0) {
            JSValueConst jargs[2] = { this_val, argv[1] };
            JS_EnqueueJob(ctx, ns_mql_initial_notify_job, 2, jargs);
        }
        if (type) JS_FreeCString(ctx, type);
    }
    return r;
}

static JSValue
ns_mql_removeListener(JSContext *ctx, JSValueConst this_val,
                      int argc, JSValueConst *argv)
{
    if (argc < 1) return JS_UNDEFINED;
    JSValueConst args[2] = { JS_NewString(ctx, "change"), argv[0] };
    JSValue r = ns_target_removeEventListener(ctx, this_val, 2, args);
    JS_FreeValue(ctx, args[0]);
    return r;
}

static gint64
ns_js_eval_budget_us(void)
{
    const ns_config *c = ns_config_get();
    int ms = c ? c->js_eval_budget_ms : 5000;
    if (ms <= 0) ms = 5000;
    if (ms > NS_JS_EVAL_BUDGET_MAX_MS) ms = NS_JS_EVAL_BUDGET_MAX_MS;
    return (gint64)ms * 1000LL;
}

#define NS_JS_MONITOR_LIMIT_US (60LL * 1000000LL)

static int
ns_js_interrupt_cb(JSRuntime *rt, void *opaque)
{
    (void)rt;
    ns_js *js = opaque;
    if (!js) return 0;
    if (js->halted) return 1;
    if (js->worker_host && g_atomic_int_get(&js->worker_host->closing)) {
        js->halted = TRUE;
        return 1;
    }
    gint64 now = g_get_monotonic_time();
    if (js->js_monitor_deadline_us != 0 && now > js->js_monitor_deadline_us) {
        js->halted = TRUE;
        g_warning("[js] monitor: page JavaScript ran longer than %d s — halting it",
                  (int)(NS_JS_MONITOR_LIMIT_US / 1000000LL));
        return 1;
    }
    if (js->eval_deadline_us == 0) return 0;
    return now > js->eval_deadline_us ? 1 : 0;
}

gboolean
ns_js_in_pump(const ns_js *js)
{
    return js && js->in_pump;
}

static void
ns_js_credit_pumped_time(ns_js *js, gint64 pump_start_us)
{
    if (!js) return;
    gint64 pumped_us = g_get_monotonic_time() - pump_start_us;
    if (pumped_us <= 0) return;
    if (js->eval_deadline_us != 0)
        js->eval_deadline_us += pumped_us;
    if (js->js_monitor_deadline_us != 0)
        js->js_monitor_deadline_us += pumped_us;
}

typedef struct {
    GMainLoop   *loop;
    ns_response *resp;
    GError      *err;
    gboolean     done;
} ns_js_pumped_fetch;

static void
ns_js_pumped_fetch_done(GObject *src, GAsyncResult *result, gpointer user_data)
{
    (void)src;
    ns_js_pumped_fetch *pf = user_data;
    pf->resp = ns_net_fetch_finish(result, &pf->err);
    pf->done = TRUE;
    if (pf->loop) g_main_loop_quit(pf->loop);
}

static ns_response *
ns_js_fetch_resource(ns_js *js, const char *url, const char *top_url,
                     const char *const *headers, GError **error)
{
    if (!js || js->worker_host)
        return ns_net_request_blocking(url, top_url, "GET", NULL, 0, NULL,
                                       headers, NULL, error);

    ns_js_pumped_fetch pf = {0};
    pf.loop = g_main_loop_new(NULL, FALSE);
    ns_net_request_async(url, top_url, "GET", NULL, 0, NULL, headers, NULL,
                         ns_js_pumped_fetch_done, &pf);
    gboolean saved = js->in_pump;
    js->in_pump = TRUE;
    gint64 pump_start_us = g_get_monotonic_time();
    if (!pf.done)
        g_main_loop_run(pf.loop);
    ns_js_credit_pumped_time(js, pump_start_us);
    js->in_pump = saved;
    g_main_loop_unref(pf.loop);
    if (pf.err) {
        if (error) *error = pf.err;
        else g_error_free(pf.err);
    }
    return pf.resp;
}

typedef struct ns_budget_guard {
    gint64 saved;
} ns_budget_guard;

static void
ns_js_budget_push(ns_js *js, ns_budget_guard *g)
{
    if (!js || !g) return;
    g->saved = js->eval_deadline_us;
    gint64 now = g_get_monotonic_time();
    if (g->saved == 0)
        js->js_monitor_deadline_us = now + NS_JS_MONITOR_LIMIT_US;
    gint64 fresh = now + ns_js_eval_budget_us();
    if (g->saved == 0 || fresh < g->saved)
        js->eval_deadline_us = fresh;
}

static void
ns_js_budget_pop(ns_js *js, ns_budget_guard *g)
{
    if (!js || !g) return;
    js->eval_deadline_us = g->saved;
    if (g->saved == 0)
        js->js_monitor_deadline_us = 0;
}

