uint32_t
ns_js_array_length(JSContext *ctx, JSValueConst arr)
{
    uint32_t len = 0;
    JSValue lv = JS_GetPropertyStr(ctx, arr, "length");
    JS_ToUint32(ctx, &len, lv);
    JS_FreeValue(ctx, lv);
    return len;
}

gboolean
ns_js_get_bool_prop(JSContext *ctx, JSValueConst obj, const char *key,
                    gboolean *was_set)
{
    JSValue v = JS_GetPropertyStr(ctx, obj, key);
    gboolean defined = !JS_IsUndefined(v);
    gboolean truthy = defined && JS_ToBool(ctx, v) > 0;
    JS_FreeValue(ctx, v);
    if (was_set) *was_set = defined;
    return truthy;
}

static int32_t
ns_js_get_int32_prop(JSContext *ctx, JSValueConst obj, const char *key,
                     int32_t fallback)
{
    JSValue v = JS_GetPropertyStr(ctx, obj, key);
    int32_t r = fallback;
    if (!JS_IsUndefined(v) && !JS_IsNull(v)) JS_ToInt32(ctx, &r, v);
    JS_FreeValue(ctx, v);
    return r;
}

static double
ns_js_get_double_prop(JSContext *ctx, JSValueConst obj, const char *key,
                      double fallback)
{
    JSValue v = JS_GetPropertyStr(ctx, obj, key);
    double r = fallback;
    if (!JS_IsUndefined(v) && !JS_IsNull(v)) JS_ToFloat64(ctx, &r, v);
    JS_FreeValue(ctx, v);
    return r;
}

static char *
ns_js_get_string_prop(JSContext *ctx, JSValueConst obj, const char *key)
{
    JSValue v = JS_GetPropertyStr(ctx, obj, key);
    char *out = NULL;
    if (JS_IsString(v)) {
        const char *s = JS_ToCString(ctx, v);
        if (s) { out = g_strdup(s); JS_FreeCString(ctx, s); }
    }
    JS_FreeValue(ctx, v);
    return out;
}

static gboolean
ns_js_bytes_view(JSContext *ctx, JSValueConst value, const uint8_t **out_data,
                 size_t *out_len, JSValue *out_holder)
{
    if (out_data) *out_data = NULL;
    if (out_len) *out_len = 0;
    if (out_holder) *out_holder = JS_UNDEFINED;

    if (JS_IsArrayBuffer(value)) {
        size_t total = 0;
        uint8_t *base = JS_GetArrayBuffer(ctx, &total, value);
        if (base) {
            if (out_data) *out_data = base;
            if (out_len) *out_len = total;
            if (out_holder) *out_holder = JS_DupValue(ctx, value);
            return TRUE;
        }
        return FALSE;
    }

    if (!JS_IsObject(value)) return FALSE;

    JSValue buf = JS_GetPropertyStr(ctx, value, "buffer");
    if (JS_IsException(buf)) {
        JS_FreeValue(ctx, JS_GetException(ctx));
        return FALSE;
    }
    if (!JS_IsArrayBuffer(buf)) {
        JS_FreeValue(ctx, buf);
        return FALSE;
    }

    JSValue off_v = JS_GetPropertyStr(ctx, value, "byteOffset");
    JSValue len_v = JS_GetPropertyStr(ctx, value, "byteLength");
    if (JS_IsException(off_v) || JS_IsException(len_v)) {
        JS_FreeValue(ctx, JS_GetException(ctx));
        JS_FreeValue(ctx, off_v);
        JS_FreeValue(ctx, len_v);
        JS_FreeValue(ctx, buf);
        return FALSE;
    }
    gboolean ok = JS_IsNumber(off_v) && JS_IsNumber(len_v);
    uint64_t byte_off = 0, byte_len = 0;
    if (ok && (JS_ToIndex(ctx, &byte_off, off_v) < 0 ||
               JS_ToIndex(ctx, &byte_len, len_v) < 0)) {
        JS_FreeValue(ctx, JS_GetException(ctx));
        ok = FALSE;
    }
    JS_FreeValue(ctx, off_v);
    JS_FreeValue(ctx, len_v);
    if (!ok) {
        JS_FreeValue(ctx, buf);
        return FALSE;
    }

    size_t total = 0;
    uint8_t *base = JS_GetArrayBuffer(ctx, &total, buf);
    if (!base || byte_off > total || byte_len > total - byte_off) {
        JS_FreeValue(ctx, buf);
        return FALSE;
    }
    if (out_data) *out_data = base + byte_off;
    if (out_len) *out_len = (size_t)byte_len;
    if (out_holder) *out_holder = buf;
    else JS_FreeValue(ctx, buf);
    return TRUE;
}

static char *
ns_js_copy_bytes(const uint8_t *data, gsize len)
{
    if (len > NS_JS_BODY_BYTES_MAX) return NULL;
    char *out = g_malloc(len + 1);
    if (len > 0 && data) memcpy(out, data, len);
    out[len] = '\0';
    return out;
}

static char *
ns_js_body_bytes(JSContext *ctx, JSValueConst value, gsize *out_len)
{
    if (out_len) *out_len = 0;
    if (JS_IsUndefined(value) || JS_IsNull(value)) return NULL;

    if (JS_IsString(value)) {
        size_t slen = 0;
        const char *s = JS_ToCStringLen(ctx, &slen, value);
        if (!s) return NULL;
        char *copy = ns_js_copy_bytes((const uint8_t *)s, (gsize)slen);
        JS_FreeCString(ctx, s);
        if (copy && out_len) *out_len = (gsize)slen;
        return copy;
    }

    const uint8_t *data = NULL;
    size_t len = 0;
    JSValue holder = JS_UNDEFINED;
    if (ns_js_bytes_view(ctx, value, &data, &len, &holder)) {
        char *copy = ns_js_copy_bytes(data, (gsize)len);
        JS_FreeValue(ctx, holder);
        if (copy && out_len) *out_len = (gsize)len;
        return copy;
    }

    if (JS_IsObject(value)) {
        JSValue b = JS_GetPropertyStr(ctx, value, "_b");
        if (JS_IsException(b)) {
            JS_FreeValue(ctx, JS_GetException(ctx));
            return NULL;
        }
        gboolean has_blob_bytes = !JS_IsUndefined(b) && !JS_IsNull(b);
        JS_FreeValue(ctx, b);
        if (has_blob_bytes) return ns_blob_bytes_as_string(ctx, value, out_len);
    }

    return NULL;
}

static gboolean
ns_js_value_is_form_data(JSContext *ctx, JSValueConst v)
{
    if (!JS_IsObject(v) || JS_IsFunction(ctx, v)) return FALSE;
    JSValue e = JS_GetPropertyStr(ctx, v, "_entries");
    gboolean is_arr = JS_IsArray(e);
    JS_FreeValue(ctx, e);
    if (!is_arr) return FALSE;
    JSValue a = JS_GetPropertyStr(ctx, v, "append");
    JSValue s = JS_GetPropertyStr(ctx, v, "getAll");
    gboolean ok = JS_IsFunction(ctx, a) && JS_IsFunction(ctx, s);
    JS_FreeValue(ctx, a);
    JS_FreeValue(ctx, s);
    return ok;
}

static gboolean
ns_js_value_is_url_search_params(JSContext *ctx, JSValueConst v)
{
    if (!JS_IsObject(v) || JS_IsFunction(ctx, v)) return FALSE;
    JSValue p = JS_GetPropertyStr(ctx, v, "_p");
    gboolean is_arr = JS_IsArray(p);
    JS_FreeValue(ctx, p);
    if (!is_arr) return FALSE;
    JSValue a = JS_GetPropertyStr(ctx, v, "append");
    JSValue s = JS_GetPropertyStr(ctx, v, "getAll");
    gboolean ok = JS_IsFunction(ctx, a) && JS_IsFunction(ctx, s);
    JS_FreeValue(ctx, a);
    JS_FreeValue(ctx, s);
    return ok;
}

static char *
ns_js_form_data_serialize(JSContext *ctx, JSValueConst fd,
                          gsize *out_len, char **out_content_type)
{
    char *boundary = ns_multipart_boundary();
    if (out_content_type)
        *out_content_type = g_strdup_printf(
            "multipart/form-data; boundary=%s", boundary);

    GString *body = g_string_new(NULL);
    JSValue entries = JS_GetPropertyStr(ctx, fd, "_entries");
    if (JS_IsArray(entries)) {
        uint32_t n = ns_js_array_length(ctx, entries);
        for (uint32_t i = 0; i < n; i++) {
            JSValue pair = JS_GetPropertyUint32(ctx, entries, i);
            if (!JS_IsArray(pair)) { JS_FreeValue(ctx, pair); continue; }
            JSValue k = JS_GetPropertyUint32(ctx, pair, 0);
            JSValue v = JS_GetPropertyUint32(ctx, pair, 1);
            JSValue fname_override = JS_GetPropertyUint32(ctx, pair, 2);
            const char *ks = JS_ToCString(ctx, k);

            JSValue b_priv = JS_IsObject(v)
                ? JS_GetPropertyStr(ctx, v, "_b") : JS_UNDEFINED;
            gboolean is_blob = !JS_IsUndefined(b_priv) && !JS_IsNull(b_priv);
            JS_FreeValue(ctx, b_priv);

            g_string_append_printf(body, "--%s\r\n", boundary);
            g_string_append(body, "Content-Disposition: form-data; name=\"");
            ns_multipart_quote_field(body, ks ? ks : "");
            g_string_append_c(body, '"');

            if (is_blob) {
                JSValue fname_v = !JS_IsUndefined(fname_override)
                    ? JS_DupValue(ctx, fname_override)
                    : JS_GetPropertyStr(ctx, v, "name");
                const char *fname = JS_IsString(fname_v)
                    ? JS_ToCString(ctx, fname_v) : NULL;
                g_string_append(body, "; filename=\"");
                ns_multipart_quote_field(body, fname ? fname : "blob");
                g_string_append(body, "\"\r\n");
                if (fname) JS_FreeCString(ctx, fname);
                JS_FreeValue(ctx, fname_v);

                JSValue type_v = JS_GetPropertyStr(ctx, v, "type");
                const char *type = JS_IsString(type_v)
                    ? JS_ToCString(ctx, type_v) : NULL;
                GString *ct = g_string_new(NULL);
                for (const char *tp = type; tp && *tp; tp++) {
                    unsigned char c = (unsigned char)*tp;
                    if (c >= 0x20 && c != 0x7f) g_string_append_c(ct, (char)c);
                }
                g_string_append_printf(body, "Content-Type: %s\r\n\r\n",
                    ct->len ? ct->str : "application/octet-stream");
                g_string_free(ct, TRUE);
                if (type) JS_FreeCString(ctx, type);
                JS_FreeValue(ctx, type_v);

                gsize blob_len = 0;
                char *blob_bytes = ns_blob_bytes_as_string(ctx, v, &blob_len);
                if (blob_bytes) {
                    g_string_append_len(body, blob_bytes, (gssize)blob_len);
                    g_free(blob_bytes);
                }
                g_string_append(body, "\r\n");
            } else {
                size_t vlen = 0;
                const char *vs = JS_ToCStringLen(ctx, &vlen, v);
                g_string_append(body, "\r\n\r\n");
                if (vs) g_string_append_len(body, vs, (gssize)vlen);
                if (vs) JS_FreeCString(ctx, vs);
                g_string_append(body, "\r\n");
            }

            if (ks) JS_FreeCString(ctx, ks);
            JS_FreeValue(ctx, k);
            JS_FreeValue(ctx, v);
            JS_FreeValue(ctx, fname_override);
            JS_FreeValue(ctx, pair);
        }
    }
    JS_FreeValue(ctx, entries);
    g_string_append_printf(body, "--%s--\r\n", boundary);
    g_free(boundary);
    if (out_len) *out_len = body->len;
    return g_string_free(body, FALSE);
}

static char *
ns_js_usp_serialize(JSContext *ctx, JSValueConst usp,
                    gsize *out_len, char **out_content_type)
{
    if (out_content_type)
        *out_content_type =
            g_strdup("application/x-www-form-urlencoded;charset=UTF-8");
    JSValue ts_fn = JS_GetPropertyStr(ctx, usp, "toString");
    JSValue str = JS_IsFunction(ctx, ts_fn)
        ? JS_Call(ctx, ts_fn, usp, 0, NULL) : JS_NewString(ctx, "");
    JS_FreeValue(ctx, ts_fn);
    if (JS_IsException(str)) {
        JS_FreeValue(ctx, JS_GetException(ctx));
        if (out_len) *out_len = 0;
        return g_strdup("");
    }
    size_t l = 0;
    const char *s = JS_ToCStringLen(ctx, &l, str);
    char *out = s ? g_strndup(s, l) : g_strdup("");
    if (s) JS_FreeCString(ctx, s);
    JS_FreeValue(ctx, str);
    if (out_len) *out_len = out ? strlen(out) : 0;
    return out;
}

void
ns_js_promise_reject(JSContext *ctx, JSValue resolvers[2], const char *message)
{
    JSValue err = JS_NewError(ctx);
    const char *colon = strchr(message, ':');
    gsize name_len = colon ? (gsize)(colon - message) : strlen(message);
    gboolean is_dom_name = name_len > 5 && name_len < 64 &&
        memcmp(message + name_len - 5, "Error", 5) == 0;
    for (gsize i = 0; is_dom_name && i < name_len; i++)
        if (!g_ascii_isalnum((guchar)message[i])) is_dom_name = FALSE;
    if (is_dom_name) {
        char *nm = g_strndup(message, name_len);
        JS_SetPropertyStr(ctx, err, "name", JS_NewString(ctx, nm));
        g_free(nm);
        const char *rest = colon ? colon + 1 : message;
        while (*rest == ' ') rest++;
        JS_SetPropertyStr(ctx, err, "message", JS_NewString(ctx, rest));
    } else {
        JS_SetPropertyStr(ctx, err, "message", JS_NewString(ctx, message));
    }
    JS_Call(ctx, resolvers[1], JS_UNDEFINED, 1, &err);
    JS_FreeValue(ctx, err);
    JS_FreeValue(ctx, resolvers[0]);
    JS_FreeValue(ctx, resolvers[1]);
}

static gboolean
ns_node_name_is_any_of(const ns_node *n, const char *const *tags)
{
    if (!n || n->kind != NS_NODE_ELEMENT || !n->name) return FALSE;
    for (; *tags; tags++)
        if (g_ascii_strcasecmp(n->name, *tags) == 0) return TRUE;
    return FALSE;
}

static void
ns_js_source_remove(ns_js *js, guint id)
{
    if (!id) return;
    GMainContext *context = js && js->main_context ? js->main_context
                                                   : g_main_context_default();
    GSource *source = g_main_context_find_source_by_id(context, id);
    if (source) g_source_destroy(source);
}

static void
ns_timer_free(gpointer data)
{
    ns_timer *t = data;
    if (!t) return;
    if (t->immediate && t->js && t->js->n_immediate_timers > 0)
        t->js->n_immediate_timers--;
    if (t->glib_source) ns_js_source_remove(t->js, t->glib_source);
    JS_FreeValue(t->js->ctx, t->cb);
    g_free(t->code);
    for (int i = 0; i < t->extra_args_count; i++)
        JS_FreeValue(t->js->ctx, t->extra_args[i]);
    g_free(t->extra_args);
    g_free(t);
}

static guint
ns_js_attach_timeout(ns_js *js, guint ms, GSourceFunc func, gpointer data)
{
    GSource *source = g_timeout_source_new(ms);
    g_source_set_callback(source, func, data, NULL);
    guint id = g_source_attach(source, js && js->main_context ? js->main_context : NULL);
    g_source_unref(source);
    return id;
}

static guint
ns_js_attach_idle(ns_js *js, GSourceFunc func, gpointer data)
{
    GSource *source = g_idle_source_new();
    g_source_set_callback(source, func, data, NULL);
    guint id = g_source_attach(source, js && js->main_context ? js->main_context : NULL);
    g_source_unref(source);
    return id;
}

static void ns_storage_drain_deferred_events(ns_js *js);

static void
ns_drain_microtasks(ns_js *js)
{
    if (!js) return;
    ns_budget_guard g = {0};
    ns_js_budget_push(js, &g);
    JSContext *ctx_out = NULL;
    int r = 0;
    js->callback_depth++;
    for (;;) {
        if (js->eval_deadline_us != 0 &&
            g_get_monotonic_time() > js->eval_deadline_us)
            break;
        if ((r = JS_ExecutePendingJob(js->rt, &ctx_out)) <= 0)
            break;
    }
    js->callback_depth--;
    if (r < 0 && js->log_cb) {
        char *msg = NULL;
        if (ctx_out) {
            JSValue ex = JS_GetException(ctx_out);
            const char *raw = JS_ToCString(ctx_out, ex);
            JSValue stack = JS_GetPropertyStr(ctx_out, ex, "stack");
            const char *stack_s = JS_IsUndefined(stack) ? NULL :
                                  JS_ToCString(ctx_out, stack);
            msg = g_strdup_printf("[error] microtask threw: %s%s%s",
                raw ? raw : "(no message)",
                stack_s ? "\n" : "", stack_s ? stack_s : "");
            if (raw) JS_FreeCString(ctx_out, raw);
            if (stack_s) JS_FreeCString(ctx_out, stack_s);
            JS_FreeValue(ctx_out, stack);
            JS_FreeValue(ctx_out, ex);
        } else {
            msg = g_strdup("[error] microtask threw");
        }
        js->log_cb(msg, js->log_user_data);
        g_free(msg);
    }
    ns_js_budget_pop(js, &g);
    ns_storage_drain_deferred_events(js);
}

static void ns_storage_flush(ns_js *js);
static void ns_storage_schedule_flush(ns_js *js);
static gboolean ns_timer_fire(gpointer data);
gboolean ns_engine_in_blocking_fetch(void);

static void
ns_js_run_due_timers(ns_js *js)
{
    if (!js || !js->ctx || js->halted || js->in_pump ||
        js->dispatch_depth > 0 || js->running_due_timers ||
        js->n_immediate_timers <= 0)
        return;
    if (ns_engine_in_blocking_fetch()) return;
    gint64 now = g_get_monotonic_time();
    int due_ids[8];
    int n_due = 0;
    GHashTableIter it;
    gpointer k, v;
    g_hash_table_iter_init(&it, js->timers);
    while (n_due < 8 && g_hash_table_iter_next(&it, &k, &v)) {
        ns_timer *t = v;
        if (!t->immediate || t->firing || !t->glib_source || t->due_us > now)
            continue;
        due_ids[n_due++] = t->id;
    }
    if (n_due == 0) return;
    js->running_due_timers = TRUE;
    for (int i = 0; i < n_due; i++) {
        ns_timer *t = g_hash_table_lookup(js->timers,
                                          GINT_TO_POINTER(due_ids[i]));
        if (!t || !t->glib_source) continue;
        ns_js_source_remove(js, t->glib_source);
        t->glib_source = 0;
        if (ns_timer_fire(t) == G_SOURCE_CONTINUE) {
            t = g_hash_table_lookup(js->timers,
                                    GINT_TO_POINTER(due_ids[i]));
            if (t && !t->glib_source)
                t->glib_source = ns_js_attach_timeout(js, 0, ns_timer_fire, t);
        }
    }
    js->running_due_timers = FALSE;
}

static void
ns_drain_mutations(ns_js *js)
{
    ns_drain_microtasks(js);
    if (js->mutated && js->mut_cb)
        js->mut_cb(js->mut_user_data);
    js->mutated = FALSE;
    ns_storage_schedule_flush(js);
    ns_js_run_due_timers(js);
}

static int
ns_nav_hardware_concurrency(void)
{
    int n = (int)g_get_num_processors();
    if (n < 1) n = 1;
    if (n > 32) n = 32;
    return n;
}

static int
ns_nav_device_memory(void)
{
#ifdef G_OS_WIN32
    MEMORYSTATUSEX status = {0};
    status.dwLength = sizeof status;
    if (GlobalMemoryStatusEx(&status)) {
        double gib = (double)status.ullTotalPhys / (1024.0 * 1024.0 * 1024.0);
        int bucket = 1;
        while ((double)bucket < gib && bucket < 4) bucket *= 2;
        return bucket;
    }
#endif
    return 4;
}

static void
ns_nav_screen_metrics(int *width, int *height,
                      int *avail_width, int *avail_height,
                      int *avail_left, int *avail_top)
{
    *width = 1920;
    *height = 1080;
    *avail_width = 1920;
    *avail_height = 1040;
    *avail_left = 0;
    *avail_top = 0;
#ifdef G_OS_WIN32
    int screen_width = GetSystemMetrics(SM_CXSCREEN);
    int screen_height = GetSystemMetrics(SM_CYSCREEN);
    if (screen_width > 0) *width = screen_width;
    if (screen_height > 0) *height = screen_height;
    RECT work_area;
    if (SystemParametersInfoW(SPI_GETWORKAREA, 0, &work_area, 0)) {
        *avail_width = work_area.right - work_area.left;
        *avail_height = work_area.bottom - work_area.top;
        *avail_left = work_area.left;
        *avail_top = work_area.top;
    }
#endif
}

static JSValue
ns_idle_deadline_time_remaining(JSContext *ctx, JSValueConst this_val,
                                int argc, JSValueConst *argv)
{
    (void)argc; (void)argv;
    JSValue v = JS_GetPropertyStr(ctx, this_val, "__tr");
    double tr = 50.0;
    if (JS_IsNumber(v)) JS_ToFloat64(ctx, &tr, v);
    JS_FreeValue(ctx, v);
    return JS_NewFloat64(ctx, tr);
}

static gboolean
ns_timer_fire(gpointer data)
{
    ns_timer *t = data;
    ns_js *js = t->js;
    if (js->halted) {
        t->glib_source = 0;
        g_hash_table_remove(js->timers, GINT_TO_POINTER(t->id));
        return G_SOURCE_REMOVE;
    }
    gboolean idle_expired = t->is_idle && t->idle_deadline_us > 0 &&
                            g_get_monotonic_time() >= t->idle_deadline_us;
    if (js->in_pump)
        return G_SOURCE_CONTINUE;
    if (ns_engine_in_blocking_fetch() && !idle_expired)
        return G_SOURCE_CONTINUE;
    t->firing = TRUE;
    int timer_id = t->id;
    gboolean is_interval = t->is_interval;
    int prev_nesting = js->timer_nesting_level;
    js->timer_nesting_level = t->nesting_level;
    ns_budget_guard bg = {0};
    ns_js_budget_push(js, &bg);

    /* The callback can clear its own timer (clearInterval(myId)) — or, via a
       re-entrant relayout/fetch, another timer that shares state — which would
       drop the last reference and free the function while it is still running.
       Hold owned copies of the callback, its code and its extra args for the
       duration of the call so the engine never executes freed memory. */
    JSValue cb = JS_IsUndefined(t->cb) ? JS_UNDEFINED
                                       : JS_DupValue(js->ctx, t->cb);
    char *code = t->code ? g_strdup(t->code) : NULL;
    int n_extra = t->extra_args_count;
    JSValue *extra = NULL;
    if (n_extra > 0) {
        extra = g_new(JSValue, n_extra);
        for (int i = 0; i < n_extra; i++)
            extra[i] = JS_DupValue(js->ctx, t->extra_args[i]);
    }

    JSValue ret;
    js->callback_depth++;
    if (code) {
        ret = JS_Eval(js->ctx, code, strlen(code), "<timer>",
                      JS_EVAL_TYPE_GLOBAL);
    } else if (t->is_idle) {
        JSValue deadline = JS_NewObject(js->ctx);
        JS_SetPropertyStr(js->ctx, deadline, "didTimeout",
                          idle_expired ? JS_TRUE : JS_FALSE);
        JS_DefinePropertyValueStr(js->ctx, deadline, "__tr",
                                  JS_NewFloat64(js->ctx, idle_expired ? 0.0 : 50.0), 0);
        JS_SetPropertyStr(js->ctx, deadline, "timeRemaining",
                          JS_NewCFunction(js->ctx, ns_idle_deadline_time_remaining,
                                          "timeRemaining", 0));
        JSValueConst args[1] = { deadline };
        ret = JS_Call(js->ctx, cb, JS_UNDEFINED, 1, args);
        JS_FreeValue(js->ctx, deadline);
    } else if (n_extra > 0) {
        ret = JS_Call(js->ctx, cb, JS_UNDEFINED, n_extra, extra);
    } else {
        ret = JS_Call(js->ctx, cb, JS_UNDEFINED, 0, NULL);
    }

    js->callback_depth--;
    JS_FreeValue(js->ctx, cb);
    g_free(code);
    if (extra) {
        for (int i = 0; i < n_extra; i++)
            JS_FreeValue(js->ctx, extra[i]);
        g_free(extra);
    }
    ns_js_budget_pop(js, &bg);
    js->timer_nesting_level = prev_nesting;
    if (JS_IsException(ret)) {
        JSValue ex = JS_GetException(js->ctx);
        const char *msg = JS_ToCString(js->ctx, ex);
        JSValue stack = JS_GetPropertyStr(js->ctx, ex, "stack");
        const char *stk = JS_IsUndefined(stack) ? NULL : JS_ToCString(js->ctx, stack);
        if (msg && js->log_cb) {
            char *line = g_strdup_printf("JS error in timer: %s%s%s",
                msg, stk ? "\n" : "", stk ? stk : "");
            js->log_cb(line, js->log_user_data);
            g_free(line);
        }
        if (stk) JS_FreeCString(js->ctx, stk);
        JS_FreeValue(js->ctx, stack);
        if (msg) JS_FreeCString(js->ctx, msg);
        ns_js_report_uncaught(js, ex, js->current_url);
        JS_FreeValue(js->ctx, ex);
    }
    JS_FreeValue(js->ctx, ret);
    ns_drain_mutations(js);
    t = g_hash_table_lookup(js->timers, GINT_TO_POINTER(timer_id));
    if (!t) return G_SOURCE_REMOVE;
    t->firing = FALSE;
    if (!is_interval) {
        t->glib_source = 0;
        g_hash_table_remove(js->timers, GINT_TO_POINTER(timer_id));
        return G_SOURCE_REMOVE;
    }
    if (t->interval_ms < 4) {
        t->interval_ms = 4;
        t->glib_source = ns_js_attach_timeout(js, 4, ns_timer_fire, t);
        return G_SOURCE_REMOVE;
    }
    return G_SOURCE_CONTINUE;
}

static gboolean
ns_timer_this_is_detached_window(ns_js *js, JSContext *ctx,
                                 JSValueConst this_val)
{
    if (!js || !JS_IsObject(this_val)) return FALSE;
    JSValue docv = JS_GetPropertyStr(ctx, this_val, "document");
    const ns_node *doc = ns_unwrap_element(docv);
    JS_FreeValue(ctx, docv);
    if (!doc || doc == js->current_doc) return FALSE;
    if (doc->kind != NS_NODE_DOCUMENT || (doc->flags & NS_NODE_FRAGMENT))
        return FALSE;
    for (const ns_node *p = doc; p; p = p->parent)
        if (p == js->current_doc) return FALSE;
    return TRUE;
}

static JSValue
ns_js_setTimeout(JSContext *ctx, JSValueConst this_val, int argc, JSValueConst *argv,
                 int is_interval)
{
    if (!js_from_ctx(ctx) || argc < 1) return JS_NewInt32(ctx, 0);
    if (ns_timer_this_is_detached_window(js_from_ctx(ctx), ctx, this_val))
        return JS_NewInt32(ctx, ++js_from_ctx(ctx)->next_timer_id);
    gboolean is_function = JS_IsFunction(ctx, argv[0]);
    char *code = NULL;
    if (!is_function) {
        const char *s = JS_ToCString(ctx, argv[0]);
        if (!s) return JS_NewInt32(ctx, 0);
        code = g_strdup(s);
        JS_FreeCString(ctx, s);
    }
    int32_t ms = 0;
    if (argc >= 2) JS_ToInt32(ctx, &ms, argv[1]);
    if (ms < 0) ms = 0;

    ns_js *js = js_from_ctx(ctx);
    int nesting = js->timer_nesting_level + 1;
    if (nesting > 5 && ms < 4) ms = 4;

    ns_timer *t = g_new0(ns_timer, 1);
    t->js = js;
    t->cb = is_function ? JS_DupValue(ctx, argv[0]) : JS_UNDEFINED;
    t->code = code;
    t->is_interval = is_interval;
    t->nesting_level = nesting;
    t->interval_ms = ms;
    if (is_function && argc > 2) {
        int n_extra = argc - 2;
        if (n_extra > 64) n_extra = 64;
        t->extra_args_count = n_extra;
        t->extra_args = g_new(JSValue, t->extra_args_count);
        for (int i = 0; i < t->extra_args_count; i++)
            t->extra_args[i] = JS_DupValue(ctx, argv[2 + i]);
    }
    t->id = ++js->next_timer_id;
    if (!is_interval && ms <= 1) {
        t->immediate = TRUE;
        t->due_us = g_get_monotonic_time() + (gint64)ms * 1000;
        js->n_immediate_timers++;
    }
    t->glib_source = ns_js_attach_timeout(js, (guint)ms, ns_timer_fire, t);
    g_hash_table_insert(js->timers, GINT_TO_POINTER(t->id), t);
    return JS_NewInt32(ctx, t->id);
}

static JSValue
ns_js_setTimeout_wrap(JSContext *ctx, JSValueConst this_val, int argc, JSValueConst *argv)
{
    return ns_js_setTimeout(ctx, this_val, argc, argv, 0);
}

static JSValue
ns_js_setInterval_wrap(JSContext *ctx, JSValueConst this_val, int argc, JSValueConst *argv)
{
    return ns_js_setTimeout(ctx, this_val, argc, argv, 1);
}

static JSValue
ns_js_clearTimer(JSContext *ctx, JSValueConst this_val, int argc, JSValueConst *argv)
{
    (void)this_val;
    if (!js_from_ctx(ctx) || argc < 1) return JS_UNDEFINED;
    int32_t id = 0;
    JS_ToInt32(ctx, &id, argv[0]);
    ns_timer *t = g_hash_table_lookup(js_from_ctx(ctx)->timers, GINT_TO_POINTER(id));
    if (t) {
        ns_js_source_remove(js_from_ctx(ctx), t->glib_source);
        t->glib_source = 0;
        g_hash_table_remove(js_from_ctx(ctx)->timers, GINT_TO_POINTER(id));
    }
    return JS_UNDEFINED;
}

