static char *
camel_to_kebab(const char *s)
{
    if (!strcmp(s, "cssFloat")) return g_strdup("float");
    if (s[0] == '-' && s[1] == '-') return g_strdup(s);
    GString *out = g_string_new(NULL);
    if (g_str_has_prefix(s, "webkit") && g_ascii_isupper(s[6]))
        g_string_append_c(out, '-');
    for (const char *p = s; *p; p++) {
        if (*p >= 'A' && *p <= 'Z') {
            g_string_append_c(out, '-');
            g_string_append_c(out, (char)(*p - 'A' + 'a'));
        } else {
            g_string_append_c(out, *p);
        }
    }
    return g_string_free(out, FALSE);
}

static gboolean
ns_style_is_prototype_name(const char *name)
{
    static const char *const reserved[] = {
        "cssText", "constructor", "length", "parentRule", "cssFloat",
        "item", "getPropertyValue", "setProperty", "removeProperty",
        "getPropertyPriority", "toString",
    };
    for (gsize i = 0; i < G_N_ELEMENTS(reserved); i++)
        if (strcmp(name, reserved[i]) == 0) return TRUE;
    return FALSE;
}

static int
ns_style_get_own_property(JSContext *ctx, JSPropertyDescriptor *desc,
                          JSValueConst obj, JSAtom prop)
{
    ns_node *n = ns_style_node(obj);
    if (!n) return 0;
    {
        JSValue key = JS_AtomToValue(ctx, prop);
        gboolean is_sym = JS_IsSymbol(key);
        JS_FreeValue(ctx, key);
        if (is_sym) return 0;
    }
    const char *name = JS_AtomToCString(ctx, prop);
    if (!name) return 0;
    if (ns_style_is_prototype_name(name)) {
        JS_FreeCString(ctx, name);
        return 0;
    }
    if (name[0] >= '0' && name[0] <= '9') {
        char *end = NULL;
        long idx = strtol(name, &end, 10);
        if (end && *end == '\0' && idx >= 0) {
            char *style = ns_inline_style_serialize(
                ns_element_get_attr(n, "style"));
            char *prop_name = NULL;
            gsize cur = 0;
            const char *p = style;
            while (p && *p) {
                while (*p == ' ' || *p == ';') p++;
                const char *colon = strchr(p, ':');
                if (!colon) break;
                if ((long)cur == idx) {
                    prop_name = g_strndup(p, (gsize)(colon - p));
                    while (*prop_name && (prop_name[strlen(prop_name)-1] == ' '))
                        prop_name[strlen(prop_name)-1] = '\0';
                    break;
                }
                const char *end_p = strchr(colon, ';');
                if (!end_p) end_p = colon + strlen(colon);
                p = end_p;
                cur++;
            }
            JS_FreeCString(ctx, name);
            g_free(style);
            if (prop_name) {
                if (desc) {
                    desc->flags = JS_PROP_CONFIGURABLE | JS_PROP_ENUMERABLE;
                    desc->value = JS_NewString(ctx, prop_name);
                    desc->getter = JS_UNDEFINED;
                    desc->setter = JS_UNDEFINED;
                }
                g_free(prop_name);
                return 1;
            }
            return 0;
        }
    }
    char *css = camel_to_kebab(name);
    JS_FreeCString(ctx, name);
    const char *style = ns_element_get_attr(n, "style");
    char *val = ns_inline_style_get(style, css);
    if (val) ns_inline_value_strip_important(val);
    char *canon = val && !(css[0] == '-' && css[1] == '-')
        ? ns_css_specified_canonical(css, val) : NULL;
    g_free(css);
    if (canon) { g_free(val); val = canon; }
    if (desc) {
        desc->flags  = JS_PROP_CONFIGURABLE | JS_PROP_ENUMERABLE | JS_PROP_WRITABLE;
        desc->value  = JS_NewString(ctx, val ? val : "");
        desc->getter = JS_UNDEFINED;
        desc->setter = JS_UNDEFINED;
    }
    g_free(val);
    return 1;
}

static JSValue
ns_style_get_length(JSContext *ctx, JSValueConst this_val)
{
    ns_node *n = ns_style_node(this_val);
    if (!n) return JS_NewInt32(ctx, 0);
    char *style = ns_inline_style_serialize(ns_element_get_attr(n, "style"));
    int32_t count = 0;
    const char *p = style;
    while (*p) {
        while (*p == ' ' || *p == ';') p++;
        if (!*p) break;
        const char *colon = strchr(p, ':');
        if (!colon) break;
        count++;
        const char *end_p = strchr(colon, ';');
        if (!end_p) break;
        p = end_p;
    }
    g_free(style);
    return JS_NewInt32(ctx, count);
}

static int
ns_style_set_property(JSContext *ctx, JSValueConst obj, JSAtom prop,
                      JSValueConst val, JSValueConst receiver, int flags)
{
    (void)receiver; (void)flags;
    ns_node *n = ns_style_node(obj);
    if (!n) return FALSE;
    ns_js *js = js_from_ctx(ctx);
    if (js && js->pinned_wrappers_set &&
        !g_hash_table_contains(js->pinned_wrappers_set, n))
        return TRUE;
    const char *name = JS_AtomToCString(ctx, prop);
    if (!name) return FALSE;
    if (strcmp(name, "cssText") == 0) {
        JS_FreeCString(ctx, name);
        const char *s = JS_ToCString(ctx, val);
        if (s) {
            ns_js_set_attr_recorded(js_from_ctx(ctx), n, "style", s);
            JS_FreeCString(ctx, s);
        }
        return TRUE;
    }
    char *css = camel_to_kebab(name);
    JS_FreeCString(ctx, name);
    const char *vstr = JS_ToCString(ctx, val);
    if (vstr && *vstr &&
        !ns_css_named_declaration_valid(css, vstr)) {
        g_free(css);
        JS_FreeCString(ctx, vstr);
        return TRUE;
    }
    const char *old = ns_element_get_attr(n, "style");
    char *new_style = ns_inline_style_set(old, css, vstr ? vstr : "");
    ns_js_set_attr_recorded(js_from_ctx(ctx), n, "style", new_style);
    g_free(new_style);
    g_free(css);
    if (vstr) JS_FreeCString(ctx, vstr);
    return TRUE;
}

static JSClassExoticMethods ns_style_exotic = {
    .get_own_property = ns_style_get_own_property,
    .set_property     = ns_style_set_property,
};

static JSClassDef ns_style_class = {
    .class_name = "CSSStyleDeclaration",
    .finalizer  = ns_style_finalizer,
    .gc_mark    = ns_style_gc_mark,
    .exotic     = &ns_style_exotic,
};

