static JSValue
ns_reflect_enum(JSContext *ctx, const ns_node *n, const ns_enum_attr_def *d)
{
    gsize vlen = 0;
    const char *v = n ? ns_element_get_attr_len(n, d->attr, &vlen) : NULL;
    if (!v) return d->missing ? JS_NewString(ctx, d->missing) : JS_NULL;
    for (gsize i = 0; i < d->nkw; i++)
        if (ns_enum_kw_eq(v, vlen, d->kw[i]))
            return JS_NewString(ctx, d->kw[i]);
    return d->invalid ? JS_NewString(ctx, d->invalid) : JS_NULL;
}

static JSValue
ns_element_enum_getter(JSContext *ctx, JSValueConst this_val, int magic)
{
    if (magic < 0 || magic >= (int)G_N_ELEMENTS(g_enum_attrs)) return JS_NULL;
    return ns_reflect_enum(ctx, ns_unwrap_element(this_val), &g_enum_attrs[magic]);
}

static JSValue
ns_element_enum_setter(JSContext *ctx, JSValueConst this_val, JSValueConst val, int magic)
{
    if (magic < 0 || magic >= (int)G_N_ELEMENTS(g_enum_attrs)) return JS_UNDEFINED;
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n) return JS_UNDEFINED;
    const ns_enum_attr_def *d = &g_enum_attrs[magic];
    if ((d->nullable || !d->missing) && (JS_IsNull(val) || JS_IsUndefined(val))) {
        ns_js_remove_attr_recorded(js_from_ctx(ctx), n, d->attr);
        return JS_UNDEFINED;
    }
    size_t len = 0;
    const char *s = JS_ToCStringLen(ctx, &len, val);
    if (s) {
        ns_js_set_attr_recorded_len(js_from_ctx(ctx), n, d->attr, s, (gssize)len);
        JS_FreeCString(ctx, s);
    }
    return JS_UNDEFINED;
}

static const char *const kw_input_types[] = {
    "text", "search", "tel", "url", "email", "password", "date", "month",
    "week", "time", "datetime-local", "number", "range", "color", "checkbox",
    "radio", "file", "submit", "image", "reset", "button", "hidden",
};
static const char *const kw_button_types[] = { "submit", "reset", "button" };

static JSValue
ns_element_get_type(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n || !n->name) return JS_NewString(ctx, "");
    if (strcmp(n->name, "input") == 0) {
        ns_enum_attr_def d = { "type", kw_input_types,
                               G_N_ELEMENTS(kw_input_types), "text", "text",
                               FALSE };
        return ns_reflect_enum(ctx, n, &d);
    }
    if (strcmp(n->name, "button") == 0) {
        ns_enum_attr_def d = { "type", kw_button_types,
                               G_N_ELEMENTS(kw_button_types), "submit", "submit",
                               FALSE };
        return ns_reflect_enum(ctx, n, &d);
    }
    if (strcmp(n->name, "select") == 0)
        return JS_NewString(ctx, ns_element_get_attr(n, "multiple")
                                     ? "select-multiple" : "select-one");
    if (strcmp(n->name, "textarea") == 0)
        return JS_NewString(ctx, "textarea");
    if (strcmp(n->name, "output") == 0)
        return JS_NewString(ctx, "output");
    if (strcmp(n->name, "fieldset") == 0)
        return JS_NewString(ctx, "fieldset");
    gsize vlen = 0;
    const char *v = ns_element_get_attr_len(n, "type", &vlen);
    return v ? JS_NewStringLen(ctx, v, vlen) : JS_NewString(ctx, "");
}

static JSValue
ns_element_set_type(JSContext *ctx, JSValueConst this_val, JSValueConst val)
{
    JSValue r = ns_element_reflect_str_set(ctx, this_val, val, "type");
    ns_node *el = ns_unwrap_element_mut(this_val);
    if (el) ns_input_resanitize_value(el);
    return r;
}

static const char *
ns_autocapitalize_canon(const char *raw)
{
    if (!raw) return NULL;
    if (!g_ascii_strcasecmp(raw, "off") || !g_ascii_strcasecmp(raw, "none"))
        return "none";
    if (!g_ascii_strcasecmp(raw, "on") || !g_ascii_strcasecmp(raw, "sentences"))
        return "sentences";
    if (!g_ascii_strcasecmp(raw, "words"))      return "words";
    if (!g_ascii_strcasecmp(raw, "characters")) return "characters";
    return NULL;
}

static gboolean
ns_element_autocapitalize_inherits(const ns_node *n)
{
    static const char *const tags[] = {
        "button", "fieldset", "input", "output", "select", "textarea", NULL,
    };
    return ns_node_name_is_any_of(n, tags);
}

static JSValue
ns_element_get_autocapitalize(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n) return JS_NewString(ctx, "");
    const char *own = ns_autocapitalize_canon(
        ns_element_get_attr(n, "autocapitalize"));
    if (own) return JS_NewString(ctx, own);
    if (ns_element_autocapitalize_inherits(n)) {
        ns_js *js = js_from_ctx(ctx);
        const ns_node *form = ns_form_owner(n, js ? js->current_doc : NULL);
        if (form) {
            const char *fown = ns_autocapitalize_canon(
                ns_element_get_attr(form, "autocapitalize"));
            if (fown) return JS_NewString(ctx, fown);
        }
    }
    return JS_NewString(ctx, "");
}

static JSValue
ns_element_set_autocapitalize(JSContext *ctx, JSValueConst this_val,
                              JSValueConst val)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n) return JS_UNDEFINED;
    const char *s = JS_ToCString(ctx, val);
    if (s) {
        ns_js_set_attr_recorded(js_from_ctx(ctx), n, "autocapitalize", s);
        JS_FreeCString(ctx, s);
    }
    return JS_UNDEFINED;
}

static JSValue
ns_element_get_spellcheck(JSContext *ctx, JSValueConst this_val)
{
    return JS_NewBool(ctx, ns_node_spellcheck_used(ns_unwrap_element(this_val)));
}

static JSValue
ns_element_set_spellcheck(JSContext *ctx, JSValueConst this_val,
                          JSValueConst val)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n) return JS_UNDEFINED;
    ns_js_set_attr_recorded(js_from_ctx(ctx), n, "spellcheck",
                            JS_ToBool(ctx, val) ? "true" : "false");
    return JS_UNDEFINED;
}

static gboolean
ns_node_in_template_content(const ns_node *n)
{
    for (const ns_node *p = n; p; p = p->parent)
        if ((p->flags & NS_NODE_TEMPLATE_CONTENT) ||
            ns_node_is_element_named(p, "template"))
            return TRUE;
    return FALSE;
}

static JSValue
ns_element_get_htmlFor(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n || (n->flags & (NS_NODE_SVG_NS | NS_NODE_FOREIGN_NS)))
        return JS_UNDEFINED;
    if (ns_node_is_element_named(n, "output"))
        return ns_make_token_list(ctx, this_val, "for");
    if (!ns_node_is_element_named(n, "label"))
        return JS_UNDEFINED;
    return ns_element_reflect_str_get(ctx, this_val, "for", FALSE);
}

static JSValue
ns_element_set_htmlFor(JSContext *ctx, JSValueConst this_val, JSValueConst val)
{
    return ns_element_reflect_str_set(ctx, this_val, val, "for");
}

static const char *kBoolAttrs[] = {
    "open", "selected", "multiple", "readonly", "autofocus",
    "controls", "loop", "muted", "autoplay", "defer", "async",
    "novalidate",
    "ismap", "draggable", "reversed", "playsinline",
    "default", "inert", "nomodule", "formnovalidate",
    "required",
};

static JSValue
ns_element_async_method(JSContext *ctx, JSValueConst this_val, int argc, JSValueConst *argv)
{
    if (argc < 1 || !JS_IsFunction(ctx, argv[0])) return JS_NewInt32(ctx, 0);
    JSValue bind = JS_GetPropertyStr(ctx, argv[0], "bind");
    JSValue cb = JS_UNDEFINED;
    if (JS_IsFunction(ctx, bind)) {
        JSValueConst args[1] = { this_val };
        cb = JS_Call(ctx, bind, argv[0], 1, args);
    }
    JS_FreeValue(ctx, bind);
    if (JS_IsException(cb)) return cb;
    if (!JS_IsFunction(ctx, cb)) {
        JS_FreeValue(ctx, cb);
        cb = JS_DupValue(ctx, argv[0]);
    }
    JSValue delay = argc > 1 ? JS_DupValue(ctx, argv[1]) : JS_NewInt32(ctx, 0);
    JSValueConst args[2] = { cb, delay };
    JSValue ret = ns_js_setTimeout(ctx, JS_UNDEFINED, 2, args, 0);
    JS_FreeValue(ctx, delay);
    JS_FreeValue(ctx, cb);
    return ret;
}

static JSValue
ns_element_cancelAsync(JSContext *ctx, JSValueConst this_val, int argc, JSValueConst *argv)
{
    return ns_js_clearTimer(ctx, this_val, argc, argv);
}

static JSValue
ns_element_boolattr_getter(JSContext *ctx, JSValueConst this_val, int magic)
{
    if (magic < 0 || magic >= (int)G_N_ELEMENTS(kBoolAttrs)) return JS_FALSE;
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n) return JS_FALSE;
    if (strcmp(kBoolAttrs[magic], "async") == 0 && !ns_node_is_element_named(n, "script"))
        return JS_NewCFunction(ctx, ns_element_async_method, "async", 2);
    return ns_element_get_attr(n, kBoolAttrs[magic]) ? JS_TRUE : JS_FALSE;
}

static JSValue
ns_element_boolattr_setter(JSContext *ctx, JSValueConst this_val, JSValueConst val, int magic)
{
    if (magic < 0 || magic >= (int)G_N_ELEMENTS(kBoolAttrs)) return JS_UNDEFINED;
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n) return JS_UNDEFINED;
    if (strcmp(kBoolAttrs[magic], "async") == 0 && !ns_node_is_element_named(n, "script")) {
        JS_DefinePropertyValueStr(ctx, this_val, "async", JS_DupValue(ctx, val),
                                  JS_PROP_WRITABLE | JS_PROP_CONFIGURABLE);
        return JS_UNDEFINED;
    }
    ns_js *_j = js_from_ctx(ctx);
    gboolean to_set = JS_ToBool(ctx, val) ? TRUE : FALSE;
    gboolean was_open = ns_element_get_attr(n, kBoolAttrs[magic]) != NULL;
    if (to_set) ns_js_set_attr_recorded(_j, n, kBoolAttrs[magic], "");
    else        ns_js_remove_attr_recorded(_j, n, kBoolAttrs[magic]);
    if (strcmp(kBoolAttrs[magic], "open") == 0 && was_open != to_set &&
        ns_node_is_element_named(n, "details"))
        ns_js_details_toggle_open(_j, n, to_set);
    return JS_UNDEFINED;
}

static gboolean
ns_element_draggable_auto_default(const ns_node *n)
{
    if (!n || n->kind != NS_NODE_ELEMENT || !n->name) return FALSE;
    if (g_ascii_strcasecmp(n->name, "img") == 0) return TRUE;
    if (g_ascii_strcasecmp(n->name, "a") == 0) {
        const char *href = ns_element_get_attr(n, "href");
        return href && *href;
    }
    return FALSE;
}

static JSValue
ns_element_get_draggable(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    const char *v = ns_element_get_attr(n, "draggable");
    if (v) {
        if (g_ascii_strcasecmp(v, "true") == 0) return JS_TRUE;
        if (g_ascii_strcasecmp(v, "false") == 0) return JS_FALSE;
    }
    return JS_NewBool(ctx, ns_element_draggable_auto_default(n));
}

static JSValue
ns_element_set_draggable(JSContext *ctx, JSValueConst this_val, JSValueConst val)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n) return JS_UNDEFINED;
    ns_js_set_attr_recorded(js_from_ctx(ctx), n, "draggable",
                            JS_ToBool(ctx, val) ? "true" : "false");
    return JS_UNDEFINED;
}

static JSValue
ns_element_get_contentEditable(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    const char *v = ns_element_get_attr(n, "contenteditable");
    if (!v) return JS_NewString(ctx, "inherit");
    if (*v == '\0' || g_ascii_strcasecmp(v, "true") == 0)
        return JS_NewString(ctx, "true");
    if (g_ascii_strcasecmp(v, "false") == 0)
        return JS_NewString(ctx, "false");
    if (g_ascii_strcasecmp(v, "plaintext-only") == 0)
        return JS_NewString(ctx, "plaintext-only");
    return JS_NewString(ctx, "inherit");
}

static JSValue
ns_element_set_contentEditable(JSContext *ctx, JSValueConst this_val, JSValueConst val)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n) return JS_UNDEFINED;
    const char *s = JS_ToCString(ctx, val);
    if (!s) return JS_EXCEPTION;
    JSValue ret = JS_UNDEFINED;
    ns_js *js = js_from_ctx(ctx);
    if (g_ascii_strcasecmp(s, "inherit") == 0)
        ns_js_remove_attr_recorded(js, n, "contenteditable");
    else if (g_ascii_strcasecmp(s, "true") == 0)
        ns_js_set_attr_recorded(js, n, "contenteditable", "true");
    else if (g_ascii_strcasecmp(s, "false") == 0)
        ns_js_set_attr_recorded(js, n, "contenteditable", "false");
    else if (g_ascii_strcasecmp(s, "plaintext-only") == 0)
        ns_js_set_attr_recorded(js, n, "contenteditable", "plaintext-only");
    else
        ret = ns_throw_dom_exception(ctx, "SyntaxError", 12,
                  "The value provided is not a valid contentEditable state.");
    JS_FreeCString(ctx, s);
    return ret;
}

static JSValue
ns_element_get_textContent(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n) return JS_NULL;
    if ((n->kind == NS_NODE_DOCUMENT && !(n->flags & NS_NODE_FRAGMENT)) ||
        n->kind == NS_NODE_DOCTYPE)
        return JS_NULL;
    if (n->kind == NS_NODE_TEXT || n->kind == NS_NODE_COMMENT)
        return JS_NewString(ctx, n->text ? n->text : "");
    char *t = ns_node_collect_all_text(n);
    JSValue v = JS_NewString(ctx, t ? t : "");
    g_free(t);
    return v;
}

typedef struct {
    GString *out;
    gboolean pending_space;
    int pending_breaks;
    gboolean have_content;
    gboolean have_text;
} ns_inner_text_ctx;

typedef enum {
    NS_IT_WS_NORMAL,
    NS_IT_WS_PRE,
    NS_IT_WS_PRE_LINE
} ns_inner_text_ws;

static gboolean
ns_inner_text_skip_tag(const char *nm)
{
    static const char *const set[] = {
        "head", "title", "meta", "link", "base",
        "noscript", "template", "datalist",
        "textarea", "iframe", "audio", "video",
        "object", "embed", "frame", "frameset", "svg", "math", NULL };
    if (!nm) return FALSE;
    for (int i = 0; set[i]; i++)
        if (g_ascii_strcasecmp(nm, set[i]) == 0) return TRUE;
    return FALSE;
}

static gboolean
ns_inner_text_is_replaced(const char *nm)
{
    static const char *const set[] = { "img", "canvas", "input", NULL };
    if (!nm) return FALSE;
    for (int i = 0; set[i]; i++)
        if (g_ascii_strcasecmp(nm, set[i]) == 0) return TRUE;
    return FALSE;
}

static gboolean
ns_inner_text_is_cell(const ns_style *s, const char *nm)
{
    if (s && ns_css_keyword_is(s->values[NS_CSS_DISPLAY], "table-cell"))
        return TRUE;
    if (s && s->values[NS_CSS_DISPLAY] &&
        s->values[NS_CSS_DISPLAY]->kind == NS_CSS_V_KEYWORD)
        return FALSE;
    return nm && (g_ascii_strcasecmp(nm, "td") == 0 ||
                  g_ascii_strcasecmp(nm, "th") == 0);
}

static gboolean
ns_inner_text_has_following_cell(ns_js *js, const ns_node *n)
{
    for (const ns_node *s = n->next_sibling; s; s = s->next_sibling) {
        if (s->kind != NS_NODE_ELEMENT) continue;
        const ns_style *st = js && js->style_table
                           ? g_hash_table_lookup(js->style_table, s) : NULL;
        if (ns_inner_text_is_cell(st, s->name)) return TRUE;
    }
    return FALSE;
}

static gboolean
ns_inner_text_is_all_ws(const char *s)
{
    if (!s) return TRUE;
    for (; *s; s++)
        if (*s != ' ' && *s != '\t' && *s != '\n' && *s != '\r' && *s != '\f')
            return FALSE;
    return TRUE;
}

static gboolean
ns_inner_text_table_container(const ns_style *s, const char *nm)
{
    static const char *const disp[] = {
        "table", "inline-table", "table-row", "table-row-group",
        "table-header-group", "table-footer-group", "table-column",
        "table-column-group", NULL };
    if (s && s->values[NS_CSS_DISPLAY] &&
        s->values[NS_CSS_DISPLAY]->kind == NS_CSS_V_KEYWORD &&
        s->values[NS_CSS_DISPLAY]->u.keyword) {
        const char *k = s->values[NS_CSS_DISPLAY]->u.keyword;
        for (int i = 0; disp[i]; i++)
            if (strcmp(k, disp[i]) == 0) return TRUE;
        return FALSE;
    }
    static const char *const tags[] = {
        "table", "thead", "tbody", "tfoot", "tr", "colgroup", "col", NULL };
    if (!nm) return FALSE;
    for (int i = 0; tags[i]; i++)
        if (g_ascii_strcasecmp(nm, tags[i]) == 0) return TRUE;
    return FALSE;
}

static gboolean
ns_inner_text_is_block(const ns_style *s, const char *nm)
{
    if (s) {
        const ns_css_value *d = s->values[NS_CSS_DISPLAY];
        if (d && d->kind == NS_CSS_V_KEYWORD && d->u.keyword) {
            const char *k = d->u.keyword;
            if (strstr(k, "inline")) return FALSE;
            if (strcmp(k, "none") == 0) return FALSE;
            if (strcmp(k, "contents") == 0) return FALSE;
            if (strcmp(k, "table-cell") == 0 ||
                strcmp(k, "table-column") == 0 ||
                strcmp(k, "table-column-group") == 0) return FALSE;
            return TRUE;
        }
    }
    static const char *const block[] = {
        "address", "article", "aside", "blockquote", "body", "dd",
        "details", "div", "dl", "dt", "fieldset", "figcaption", "figure",
        "footer", "form", "h1", "h2", "h3", "h4", "h5", "h6", "header",
        "hgroup", "hr", "html", "li", "main", "nav", "ol", "optgroup",
        "option", "p", "pre", "section", "summary", "table", "tbody",
        "tfoot", "thead", "tr", "ul", NULL };
    if (!nm) return FALSE;
    for (int i = 0; block[i]; i++)
        if (g_ascii_strcasecmp(nm, block[i]) == 0) return TRUE;
    return FALSE;
}

static ns_inner_text_ws
ns_inner_text_ws_mode(const ns_style *s, const char *nm, ns_inner_text_ws inherited)
{
    if (s) {
        const ns_css_value *w = s->values[NS_CSS_WHITE_SPACE];
        if (w && w->kind == NS_CSS_V_KEYWORD && w->u.keyword) {
            const char *k = w->u.keyword;
            if (strcmp(k, "pre") == 0 || strcmp(k, "pre-wrap") == 0 ||
                strcmp(k, "break-spaces") == 0)
                return NS_IT_WS_PRE;
            if (strcmp(k, "pre-line") == 0)
                return NS_IT_WS_PRE_LINE;
            if (strcmp(k, "normal") == 0 || strcmp(k, "nowrap") == 0)
                return NS_IT_WS_NORMAL;
        }
    }
    if (nm && (g_ascii_strcasecmp(nm, "pre") == 0 ||
               g_ascii_strcasecmp(nm, "listing") == 0 ||
               g_ascii_strcasecmp(nm, "xmp") == 0))
        return NS_IT_WS_PRE;
    return inherited;
}

static gboolean
ns_inner_text_visible(const ns_style *s, gboolean inherited)
{
    if (s) {
        const ns_css_value *v = s->values[NS_CSS_VISIBILITY];
        if (v && v->kind == NS_CSS_V_KEYWORD && v->u.keyword) {
            const char *k = v->u.keyword;
            if (strcmp(k, "hidden") == 0 || strcmp(k, "collapse") == 0)
                return FALSE;
            if (strcmp(k, "visible") == 0)
                return TRUE;
        }
    }
    return inherited;
}

static const char *
ns_inner_text_transform(const ns_style *s)
{
    if (!s) return NULL;
    const ns_css_value *t = s->values[NS_CSS_TEXT_TRANSFORM];
    if (t && t->kind == NS_CSS_V_KEYWORD && t->u.keyword) {
        const char *k = t->u.keyword;
        if (strcmp(k, "uppercase") == 0 || strcmp(k, "lowercase") == 0 ||
            strcmp(k, "capitalize") == 0)
            return k;
    }
    return NULL;
}

static void
ns_inner_text_materialize_breaks(ns_inner_text_ctx *c)
{
    if (!c->have_text) { c->pending_breaks = 0; if (!c->have_content) c->pending_space = FALSE; return; }
    if (c->pending_breaks > 0) {
        if (c->have_text) {
            for (int i = 0; i < c->pending_breaks; i++)
                g_string_append_c(c->out, '\n');
        }
        c->pending_breaks = 0;
        c->pending_space = FALSE;
    }
}

static void
ns_inner_text_require_break(ns_inner_text_ctx *c, int count)
{
    if (count > c->pending_breaks) c->pending_breaks = count;
    c->pending_space = FALSE;
}

static void
ns_inner_text_emit_glyph(ns_inner_text_ctx *c, char ch)
{
    ns_inner_text_materialize_breaks(c);
    if (c->pending_space) {
        if (c->have_content) g_string_append_c(c->out, ' ');
        c->pending_space = FALSE;
    }
    g_string_append_c(c->out, ch);
    c->have_content = TRUE;
    c->have_text = TRUE;
}

static void
ns_inner_text_forced_break(ns_inner_text_ctx *c)
{
    ns_inner_text_materialize_breaks(c);
    c->pending_space = FALSE;
    g_string_append_c(c->out, '\n');
    c->have_content = FALSE;
    c->have_text = TRUE;
}

static void
ns_inner_text_emit_replaced(ns_inner_text_ctx *c)
{
    ns_inner_text_materialize_breaks(c);
    if (c->pending_space) {
        if (c->have_content) g_string_append_c(c->out, ' ');
        c->pending_space = FALSE;
    }
    c->have_content = TRUE;
}

static void
ns_inner_text_emit_tab(ns_inner_text_ctx *c)
{
    ns_inner_text_materialize_breaks(c);
    c->pending_space = FALSE;
    g_string_append_c(c->out, '\t');
    c->have_content = TRUE;
    c->have_text = TRUE;
}

static char *
ns_inner_text_apply_transform(const char *src, const char *tt)
{
    if (!src || !tt) return NULL;
    if (strcmp(tt, "uppercase") == 0) return g_utf8_strup(src, -1);
    if (strcmp(tt, "lowercase") == 0) return g_utf8_strdown(src, -1);
    if (strcmp(tt, "capitalize") == 0) {
        GString *out = g_string_new(NULL);
        gboolean at_word_start = TRUE;
        for (const char *p = src; *p; ) {
            gunichar ch = g_utf8_get_char(p);
            const char *next = g_utf8_next_char(p);
            if (g_unichar_isspace(ch) || ch == '-' || ch == '/') {
                g_string_append_len(out, p, next - p);
                at_word_start = TRUE;
            } else if (at_word_start) {
                char buf[8];
                gint nb = g_unichar_to_utf8(g_unichar_totitle(ch), buf);
                g_string_append_len(out, buf, nb);
                at_word_start = FALSE;
            } else {
                g_string_append_len(out, p, next - p);
            }
            p = next;
        }
        return g_string_free(out, FALSE);
    }
    return NULL;
}

static void
ns_inner_text_emit_text(ns_inner_text_ctx *c, const char *t,
                        ns_inner_text_ws ws, const char *tt)
{
    if (!t) return;
    char *xf = tt ? ns_inner_text_apply_transform(t, tt) : NULL;
    const char *src = xf ? xf : t;
    for (const char *p = src; *p; p++) {
        unsigned char ch = (unsigned char)*p;
        if (ws == NS_IT_WS_PRE) {
            if (ch == '\r') continue;
            if (ch == '\n') ns_inner_text_forced_break(c);
            else ns_inner_text_emit_glyph(c, *p);
        } else if (ws == NS_IT_WS_PRE_LINE && (ch == '\n' || ch == '\r')) {
            ns_inner_text_forced_break(c);
        } else if (ch == ' ' || ch == '\t' || ch == '\n' ||
                   ch == '\r' || ch == '\f') {
            c->pending_space = TRUE;
        } else {
            ns_inner_text_emit_glyph(c, *p);
        }
    }
    g_free(xf);
}

static gboolean
ns_inner_text_blockifies_children(const ns_style *s)
{
    if (!s) return FALSE;
    const ns_css_value *d = s->values[NS_CSS_DISPLAY];
    if (d && d->kind == NS_CSS_V_KEYWORD && d->u.keyword) {
        const char *k = d->u.keyword;
        if (strstr(k, "flex") || strstr(k, "grid")) return TRUE;
    }
    return FALSE;
}

static gboolean
ns_inner_text_rendered_child(const ns_node *parent, const ns_node *child)
{
    if (!parent || !parent->name || !child) return TRUE;
    gboolean child_is = child->kind == NS_NODE_ELEMENT && child->name;
    if (g_ascii_strcasecmp(parent->name, "select") == 0)
        return child_is &&
               (g_ascii_strcasecmp(child->name, "option") == 0 ||
                g_ascii_strcasecmp(child->name, "optgroup") == 0);
    if (g_ascii_strcasecmp(parent->name, "optgroup") == 0)
        return child_is && g_ascii_strcasecmp(child->name, "option") == 0;
    return TRUE;
}

static void
ns_inner_text_collect(ns_js *js, const ns_node *n, ns_inner_text_ctx *c,
                      ns_inner_text_ws ws, gboolean visible, const char *tt,
                      gboolean force_block, int depth, gboolean is_root);

static gboolean
ns_inner_text_is_atomic_inline(const ns_style *s)
{
    if (!s) return FALSE;
    const ns_css_value *d = s->values[NS_CSS_DISPLAY];
    if (d && d->kind == NS_CSS_V_KEYWORD && d->u.keyword) {
        const char *k = d->u.keyword;
        return strcmp(k, "inline-block") == 0 ||
               strcmp(k, "inline-flex") == 0 ||
               strcmp(k, "inline-grid") == 0 ||
               strcmp(k, "inline-table") == 0;
    }
    return FALSE;
}

static void
ns_inner_text_collect_children(ns_js *js, const ns_node *n, ns_inner_text_ctx *c,
                               ns_inner_text_ws child_ws, gboolean child_visible,
                               const char *child_tt, gboolean child_block, int depth)
{
    gboolean details_closed = n->name &&
        g_ascii_strcasecmp(n->name, "details") == 0 &&
        !ns_element_get_attr(n, "open");
    for (const ns_node *ch = n->first_child; ch; ch = ch->next_sibling) {
        if (details_closed &&
            !(ch->kind == NS_NODE_ELEMENT && ch->name &&
              g_ascii_strcasecmp(ch->name, "summary") == 0))
            continue;
        if (!ns_inner_text_rendered_child(n, ch)) continue;
        ns_inner_text_collect(js, ch, c, child_ws, child_visible, child_tt,
                              child_block, depth + 1, FALSE);
        if (ch->kind == NS_NODE_ELEMENT) {
            const ns_style *cs = js && js->style_table
                ? g_hash_table_lookup(js->style_table, ch) : NULL;
            if (ns_inner_text_is_cell(cs, ch->name) &&
                ns_inner_text_has_following_cell(js, ch))
                ns_inner_text_emit_tab(c);
        }
        if (details_closed) break;
    }
}

static void
ns_inner_text_collect(ns_js *js, const ns_node *n, ns_inner_text_ctx *c,
                      ns_inner_text_ws ws, gboolean visible, const char *tt,
                      gboolean force_block, int depth, gboolean is_root)
{
    if (!n || depth >= 512) return;
    if (n->kind == NS_NODE_TEXT) {
        if (!visible || !n->text) return;
        if (n->parent && ns_inner_text_is_all_ws(n->text)) {
            const ns_style *ps = js && js->style_table
                ? g_hash_table_lookup(js->style_table, n->parent) : NULL;
            if (ns_inner_text_table_container(ps, n->parent->name)) return;
        }
        ns_inner_text_emit_text(c, n->text, ws, tt);
        return;
    }
    if (n->kind != NS_NODE_ELEMENT) return;
    if (ns_inner_text_skip_tag(n->name)) return;
    if (n->flags & (NS_NODE_SVG_NS | NS_NODE_FOREIGN_NS)) return;
    const ns_style *s = js && js->style_table
                      ? g_hash_table_lookup(js->style_table, n) : NULL;
    if (s && ns_css_keyword_is(s->values[NS_CSS_DISPLAY], "none")) return;
    if (!s && n->name && (g_ascii_strcasecmp(n->name, "script") == 0 ||
                          g_ascii_strcasecmp(n->name, "style") == 0))
        return;
    ns_inner_text_ws child_ws = ns_inner_text_ws_mode(s, n->name, ws);
    gboolean child_visible = ns_inner_text_visible(s, visible);
    const char *own_tt = ns_inner_text_transform(s);
    const char *child_tt = own_tt ? own_tt : tt;
    gboolean child_block = ns_inner_text_blockifies_children(s);
    int breaks = 0;
    if (ns_inner_text_is_replaced(n->name)) {
        if (is_root || !ns_inner_text_visible(s, visible)) return;
        if (ns_inner_text_is_block(s, n->name)) {
            ns_inner_text_require_break(c, 1);
            c->have_content = TRUE;
            ns_inner_text_require_break(c, 1);
        } else {
            ns_inner_text_emit_replaced(c);
        }
        return;
    }
    if (!is_root) {
        if (n->name && g_ascii_strcasecmp(n->name, "br") == 0) {
            ns_inner_text_forced_break(c);
            return;
        }
        gboolean intrinsic_break = n->name &&
            (g_ascii_strcasecmp(n->name, "p") == 0 ||
             g_ascii_strcasecmp(n->name, "select") == 0);
        if (ns_inner_text_is_atomic_inline(s) && !intrinsic_break) {
            ns_inner_text_ctx sub = { g_string_new(NULL), FALSE, 0, FALSE, FALSE };
            ns_inner_text_collect_children(js, n, &sub, child_ws, child_visible,
                                           child_tt, child_block, depth);
            char *inner = g_string_free(sub.out, FALSE);
            if (inner && *inner) {
                ns_inner_text_materialize_breaks(c);
                if (c->pending_space && c->have_content)
                    g_string_append_c(c->out, ' ');
                c->pending_space = FALSE;
                g_string_append(c->out, inner);
                c->have_content = TRUE;
                c->have_text = TRUE;
            } else {
                ns_inner_text_emit_replaced(c);
            }
            g_free(inner);
            return;
        }
        gboolean is_p = n->name && g_ascii_strcasecmp(n->name, "p") == 0;
        gboolean block = force_block || ns_inner_text_is_block(s, n->name);
        breaks = is_p ? 2 : (block ? 1 : 0);
        if (breaks) ns_inner_text_require_break(c, breaks);
    }
    ns_inner_text_collect_children(js, n, c, child_ws, child_visible, child_tt,
                                   child_block, depth);
    if (!is_root && breaks) ns_inner_text_require_break(c, breaks);
}

static gboolean
ns_inner_outer_text_unsupported(const ns_node *n)
{
    if (!n || n->kind != NS_NODE_ELEMENT) return TRUE;
    if (n->flags & (NS_NODE_SVG_NS | NS_NODE_FOREIGN_NS)) return TRUE;
    return ns_node_is_element_named(n, "svg") || ns_node_is_element_named(n, "math");
}

static JSValue
ns_element_get_innerText(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n) return JS_NULL;
    if (ns_inner_outer_text_unsupported(n)) return JS_UNDEFINED;
    if (ns_node_is_element_named(n, "iframe") ||
        ns_node_is_element_named(n, "frame") ||
        ns_node_is_element_named(n, "frameset"))
        return JS_NewString(ctx, "");
    ns_js *js = js_from_ctx(ctx);
    if (js) ns_js_flush_layout(js);
    if (!js || !js->style_table)
        return ns_element_get_textContent(ctx, this_val);
    if (n->kind == NS_NODE_ELEMENT) {
        const ns_style *s = g_hash_table_lookup(js->style_table, n);
        if (s && ns_css_keyword_is(s->values[NS_CSS_DISPLAY], "none"))
            return ns_element_get_textContent(ctx, this_val);
    }
    ns_inner_text_ctx c = { g_string_new(NULL), FALSE, 0, FALSE, FALSE };
    ns_inner_text_collect(js, n, &c, NS_IT_WS_NORMAL, TRUE, NULL, FALSE, 0, TRUE);
    JSValue v = JS_NewString(ctx, c.out->str);
    g_string_free(c.out, TRUE);
    return v;
}

static JSValue
ns_element_get_text(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n || n->kind != NS_NODE_ELEMENT || !n->name) return JS_UNDEFINED;
    if (g_ascii_strcasecmp(n->name, "option") == 0) {
        char *t = ns_option_text_dup(n);
        JSValue v = JS_NewString(ctx, t ? t : "");
        g_free(t);
        return v;
    }
    if (g_ascii_strcasecmp(n->name, "a") == 0)
        return ns_element_get_textContent(ctx, this_val);
    if (g_ascii_strcasecmp(n->name, "script") == 0 ||
        g_ascii_strcasecmp(n->name, "title") == 0) {
        GString *buf = g_string_new(NULL);
        for (const ns_node *c = n->first_child; c; c = c->next_sibling)
            if (c->kind == NS_NODE_TEXT && c->text)
                g_string_append(buf, c->text);
        JSValue v = JS_NewString(ctx, buf->str ? buf->str : "");
        g_string_free(buf, TRUE);
        return v;
    }
    return JS_UNDEFINED;
}

static JSValue
ns_element_set_text(JSContext *ctx, JSValueConst this_val, JSValueConst val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n || n->kind != NS_NODE_ELEMENT || !n->name) return JS_UNDEFINED;
    if (g_ascii_strcasecmp(n->name, "option") == 0 ||
        g_ascii_strcasecmp(n->name, "a")      == 0 ||
        g_ascii_strcasecmp(n->name, "script") == 0 ||
        g_ascii_strcasecmp(n->name, "title")  == 0)
        return ns_element_set_textContent(ctx, this_val, val);
    JS_DefinePropertyValueStr(ctx, this_val, "text", JS_DupValue(ctx, val),
                              JS_PROP_C_W_E);
    return JS_UNDEFINED;
}

static JSValue ns_element_get_select_length(JSContext *ctx, JSValueConst this_val);
static JSValue ns_element_get_form_elements(JSContext *ctx, JSValueConst this_val);
static JSValue ns_array_item(JSContext *ctx, JSValueConst this_val,
                             int argc, JSValueConst *argv);
static JSValue ns_array_namedItem(JSContext *ctx, JSValueConst this_val,
                                  int argc, JSValueConst *argv);
static JSValue ns_form_elements_named_lookup(JSContext *ctx,
                                             JSValueConst this_val,
                                             const char *name);

static glong
ns_utf16_length(const char *s)
{
    glong units = 0;
    for (const char *p = s; *p; p = g_utf8_next_char(p))
        units += (g_utf8_get_char(p) > 0xFFFF) ? 2 : 1;
    return units;
}

static const char *
ns_utf16_offset_to_ptr(const char *s, glong offset)
{
    glong units = 0;
    const char *p = s;
    while (*p && units < offset) {
        glong w = (g_utf8_get_char(p) > 0xFFFF) ? 2 : 1;
        if (units + w > offset) break;
        units += w;
        p = g_utf8_next_char(p);
    }
    return p;
}

static gboolean
ns_cdata_uint_arg(JSContext *ctx, JSValueConst v, uint32_t *out)
{
    int32_t t = 0;
    if (JS_ToInt32(ctx, &t, v)) return FALSE;
    *out = (uint32_t)t;
    return TRUE;
}

static void
ns_cdata_splice(ns_node *n, glong off_units, glong cnt_units,
                const char *ins, gsize ins_len)
{
    const char *cur = n->text ? n->text : "";
    const char *start = ns_utf16_offset_to_ptr(cur, off_units);
    const char *end = ns_utf16_offset_to_ptr(start, cnt_units);
    gsize head = (gsize)(start - cur);
    gsize tail = strlen(end);
    char *merged = g_malloc(head + ins_len + tail + 1);
    memcpy(merged, cur, head);
    if (ins_len) memcpy(merged + head, ins, ins_len);
    memcpy(merged + head + ins_len, end, tail);
    merged[head + ins_len + tail] = '\0';
    ns_node_replace_text_owned(n, merged);
}

static JSValue
ns_element_get_text_length(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n) return JS_NewInt32(ctx, 0);
    if (n->kind == NS_NODE_TEXT || n->kind == NS_NODE_COMMENT)
        return JS_NewInt32(ctx, n->text ? (int)ns_utf16_length(n->text) : 0);
    if (n->name && g_ascii_strcasecmp(n->name, "select") == 0)
        return ns_element_get_select_length(ctx, this_val);
    if (n->name && g_ascii_strcasecmp(n->name, "form") == 0) {
        JSValue arr = ns_element_get_form_elements(ctx, this_val);
        JSValue len_v = JS_GetPropertyStr(ctx, arr, "length");
        JS_FreeValue(ctx, arr);
        return len_v;
    }
    return JS_UNDEFINED;
}

static JSValue
ns_element_substring_data(JSContext *ctx, JSValueConst this_val,
                          int argc, JSValueConst *argv)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n) return JS_NewString(ctx, "");
    if (argc < 2)
        return JS_ThrowTypeError(ctx, "2 arguments required, but only %d present", argc);
    uint32_t off = 0, cnt = 0;
    if (!ns_cdata_uint_arg(ctx, argv[0], &off)) return JS_EXCEPTION;
    if (!ns_cdata_uint_arg(ctx, argv[1], &cnt)) return JS_EXCEPTION;
    const char *cur = n->text ? n->text : "";
    glong total = ns_utf16_length(cur);
    if ((glong)off > total)
        return ns_throw_dom_exception(ctx, "IndexSizeError", 1,
            "offset is greater than length");
    glong end_units = ((guint64)off + cnt > (guint64)total) ? total : (glong)(off + cnt);
    const char *start = ns_utf16_offset_to_ptr(cur, (glong)off);
    const char *end   = ns_utf16_offset_to_ptr(cur, end_units);
    return JS_NewStringLen(ctx, start, (gsize)(end - start));
}

static JSValue
ns_element_append_data(JSContext *ctx, JSValueConst this_val,
                       int argc, JSValueConst *argv)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n) return JS_UNDEFINED;
    if (argc < 1)
        return JS_ThrowTypeError(ctx, "1 argument required, but only 0 present");
    const char *s = JS_ToCString(ctx, argv[0]);
    if (!s) return JS_EXCEPTION;
    char *old_copy = g_strdup(n->text ? n->text : "");
    char *merged = g_strconcat(n->text ? n->text : "", s, NULL);
    ns_node_replace_text_owned(n, merged);
    JS_FreeCString(ctx, s);
    { ns_js *_j = js_from_ctx(ctx);
      if (_j) { _j->mutated = TRUE; ns_js_record_character_data(_j, n, old_copy); } }
    g_free(old_copy);
    return JS_UNDEFINED;
}

static JSValue
ns_element_delete_data(JSContext *ctx, JSValueConst this_val,
                       int argc, JSValueConst *argv)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n) return JS_UNDEFINED;
    if (argc < 2)
        return JS_ThrowTypeError(ctx, "2 arguments required, but only %d present", argc);
    uint32_t off = 0, cnt = 0;
    if (!ns_cdata_uint_arg(ctx, argv[0], &off)) return JS_EXCEPTION;
    if (!ns_cdata_uint_arg(ctx, argv[1], &cnt)) return JS_EXCEPTION;
    glong total = ns_utf16_length(n->text ? n->text : "");
    if ((glong)off > total)
        return ns_throw_dom_exception(ctx, "IndexSizeError", 1,
            "offset is greater than length");
    glong cnt_units = ((guint64)off + cnt > (guint64)total) ? total - (glong)off : (glong)cnt;
    char *old_copy = g_strdup(n->text ? n->text : "");
    ns_cdata_splice(n, (glong)off, cnt_units, NULL, 0);
    { ns_js *_j = js_from_ctx(ctx);
      if (_j) { _j->mutated = TRUE; ns_js_record_character_data(_j, n, old_copy); } }
    g_free(old_copy);
    return JS_UNDEFINED;
}

static JSValue
ns_element_insert_data(JSContext *ctx, JSValueConst this_val,
                       int argc, JSValueConst *argv)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n) return JS_UNDEFINED;
    if (argc < 2)
        return JS_ThrowTypeError(ctx, "2 arguments required, but only %d present", argc);
    uint32_t off = 0;
    if (!ns_cdata_uint_arg(ctx, argv[0], &off)) return JS_EXCEPTION;
    const char *ins = JS_ToCString(ctx, argv[1]);
    if (!ins) return JS_EXCEPTION;
    glong total = ns_utf16_length(n->text ? n->text : "");
    if ((glong)off > total) {
        JS_FreeCString(ctx, ins);
        return ns_throw_dom_exception(ctx, "IndexSizeError", 1,
            "offset is greater than length");
    }
    char *old_copy = g_strdup(n->text ? n->text : "");
    ns_cdata_splice(n, (glong)off, 0, ins, strlen(ins));
    JS_FreeCString(ctx, ins);
    { ns_js *_j = js_from_ctx(ctx);
      if (_j) { _j->mutated = TRUE; ns_js_record_character_data(_j, n, old_copy); } }
    g_free(old_copy);
    return JS_UNDEFINED;
}

static JSValue
ns_element_replace_data(JSContext *ctx, JSValueConst this_val,
                        int argc, JSValueConst *argv)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n) return JS_UNDEFINED;
    if (argc < 3)
        return JS_ThrowTypeError(ctx, "3 arguments required, but only %d present", argc);
    uint32_t off = 0, cnt = 0;
    if (!ns_cdata_uint_arg(ctx, argv[0], &off)) return JS_EXCEPTION;
    if (!ns_cdata_uint_arg(ctx, argv[1], &cnt)) return JS_EXCEPTION;
    const char *ins = JS_ToCString(ctx, argv[2]);
    if (!ins) return JS_EXCEPTION;
    glong total = ns_utf16_length(n->text ? n->text : "");
    if ((glong)off > total) {
        JS_FreeCString(ctx, ins);
        return ns_throw_dom_exception(ctx, "IndexSizeError", 1,
            "offset is greater than length");
    }
    glong cnt_units = ((guint64)off + cnt > (guint64)total) ? total - (glong)off : (glong)cnt;
    char *old_copy = g_strdup(n->text ? n->text : "");
    ns_cdata_splice(n, (glong)off, cnt_units, ins, strlen(ins));
    JS_FreeCString(ctx, ins);
    { ns_js *_j = js_from_ctx(ctx);
      if (_j) { _j->mutated = TRUE; ns_js_record_character_data(_j, n, old_copy); } }
    g_free(old_copy);
    return JS_UNDEFINED;
}

static JSValue
ns_element_split_text(JSContext *ctx, JSValueConst this_val,
                      int argc, JSValueConst *argv)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n || n->kind != NS_NODE_TEXT || !n->text) return JS_NULL;
    if (argc < 1)
        return JS_ThrowTypeError(ctx, "1 argument required, but only 0 present");
    uint32_t off = 0;
    if (!ns_cdata_uint_arg(ctx, argv[0], &off)) return JS_EXCEPTION;
    glong total = ns_utf16_length(n->text);
    if ((glong)off > total)
        return ns_throw_dom_exception(ctx, "IndexSizeError", 1,
            "offset is greater than length");
    const char *split = ns_utf16_offset_to_ptr(n->text, (glong)off);
    char *tail_text = g_strdup(split);
    gsize head_len = (gsize)(split - n->text);
    char *head = g_strndup(n->text, head_len);
    ns_node_replace_text_owned(n, head);
    ns_node *tail = ns_node_new_text(tail_text);
    ns_js *_j = js_from_ctx(ctx);
    if (n->parent) {
        tail->parent = n->parent;
        tail->prev_sibling = n;
        tail->next_sibling = n->next_sibling;
        if (n->next_sibling) n->next_sibling->prev_sibling = tail;
        else n->parent->last_child = tail;
        n->next_sibling = tail;
        if (_j)
            ns_js_record_child_change(_j, n->parent, tail, NULL,
                                      tail->prev_sibling, tail->next_sibling);
    } else if (_j) {
        g_hash_table_add(_j->orphan_nodes, tail);
    }
    if (_j) _j->mutated = TRUE;
    return ns_make_element(ctx, tail);
}

static JSValue
ns_element_get_nodeValue(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n) return JS_NULL;
    if (n->kind == NS_NODE_TEXT || n->kind == NS_NODE_COMMENT)
        return JS_NewString(ctx, n->text ? n->text : "");
    return JS_NULL;
}

static JSValue
ns_element_get_wholeText(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n || n->kind != NS_NODE_TEXT) return JS_UNDEFINED;
    const ns_node *start = n;
    while (start->prev_sibling && start->prev_sibling->kind == NS_NODE_TEXT)
        start = start->prev_sibling;
    GString *s = g_string_new(NULL);
    for (const ns_node *c = start; c && c->kind == NS_NODE_TEXT;
         c = c->next_sibling)
        g_string_append(s, c->text ? c->text : "");
    JSValue v = JS_NewStringLen(ctx, s->str, s->len);
    g_string_free(s, TRUE);
    return v;
}

static JSValue
ns_text_replaceWholeText(JSContext *ctx, JSValueConst this_val,
                         int argc, JSValueConst *argv)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n || n->kind != NS_NODE_TEXT) return JS_NULL;
    const char *content = argc > 0 && !JS_IsNull(argv[0]) && !JS_IsUndefined(argv[0])
        ? JS_ToCString(ctx, argv[0]) : NULL;
    gboolean empty = !content || !*content;
    ns_node *parent = n->parent;
    ns_node *start = n;
    while (start->prev_sibling && start->prev_sibling->kind == NS_NODE_TEXT)
        start = start->prev_sibling;
    ns_js *js = js_from_ctx(ctx);
    ns_node *result = NULL;
    ns_node *c = start;
    while (c && c->kind == NS_NODE_TEXT) {
        ns_node *next = c->next_sibling;
        if (!empty && c == n) {
            char *old_copy = c->text ? g_strdup(c->text) : g_strdup("");
            ns_node_replace_text_owned(c, g_strdup(content));
            if (js) ns_js_record_character_data(js, c, old_copy);
            g_free(old_copy);
            result = c;
        } else {
            ns_node_remove(c);
            ns_js_orphan_node(js, c);
        }
        c = next;
    }
    if (js) {
        js->mutated = TRUE;
        ns_qcache_invalidate(js);
        if (parent) ns_css_mark_restyle_dirty(parent);
    }
    if (content) JS_FreeCString(ctx, content);
    return result ? ns_make_element(ctx, result) : JS_NULL;
}

static JSValue
ns_element_set_nodeValue(JSContext *ctx, JSValueConst this_val, JSValueConst val)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n) return JS_UNDEFINED;
    if (n->kind != NS_NODE_TEXT && n->kind != NS_NODE_COMMENT) return JS_UNDEFINED;
    gboolean free_s = !JS_IsNull(val) && !JS_IsUndefined(val);
    const char *s = free_s ? JS_ToCString(ctx, val) : "";
    if (s) {
        char *old_copy = n->text ? g_strdup(n->text) : g_strdup("");
        ns_node_replace_text_owned(n, g_strdup(s));
        if (free_s) JS_FreeCString(ctx, s);
        ns_js *_j = js_from_ctx(ctx);
        if (_j) {
            _j->mutated = TRUE;
            ns_js_record_character_data(_j, n, old_copy);
        }
        g_free(old_copy);
    }
    return JS_UNDEFINED;
}

static gboolean
ns_node_is_object_element(const ns_node *n)
{
    return n && n->kind == NS_NODE_ELEMENT && n->name &&
           g_ascii_strcasecmp(n->name, "object") == 0;
}

static JSValue
ns_element_get_data(JSContext *ctx, JSValueConst this_val)
{
    const ns_node *n = ns_unwrap_element(this_val);
    if (ns_node_is_object_element(n)) {
        const char *v = ns_element_get_attr(n, "data");
        if (!v || !*v) return JS_NewString(ctx, "");
        ns_js *js = js_from_ctx(ctx);
        const char *base = js ? js->current_url : NULL;
        if (base && *base) {
            char *resolved = ns_url_resolve(base, v);
            if (resolved) {
                JSValue ret = JS_NewString(ctx, resolved);
                g_free(resolved);
                return ret;
            }
        }
        return JS_NewString(ctx, v);
    }
    return ns_element_get_nodeValue(ctx, this_val);
}

static JSValue
ns_element_set_data(JSContext *ctx, JSValueConst this_val, JSValueConst val)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (ns_node_is_object_element(n)) {
        const char *s = JS_ToCString(ctx, val);
        if (s) {
            ns_js *js = js_from_ctx(ctx);
            const char *old = ns_element_get_attr(n, "data");
            gboolean changed = !old || strcmp(old, s) != 0;
            ns_js_set_attr_recorded(js, n, "data", s);
            if (changed) ns_js_schedule_iframe_load(js, n);
            JS_FreeCString(ctx, s);
        }
        return JS_UNDEFINED;
    }
    if (n && n->kind == NS_NODE_ELEMENT) {
        JS_DefinePropertyValueStr(ctx, this_val, "data",
                                  JS_DupValue(ctx, val), JS_PROP_C_W_E);
        return JS_UNDEFINED;
    }
    return ns_element_set_nodeValue(ctx, this_val, val);
}

