static JSValue
ns_window_btoa(JSContext *ctx, JSValueConst this_val,
               int argc, JSValueConst *argv)
{
    (void)this_val;
    if (argc < 1) return JS_NewString(ctx, "");
    size_t slen = 0;
    const char *s = JS_ToCStringLen(ctx, &slen, argv[0]);
    if (!s) return JS_NewString(ctx, "");
    GByteArray *bytes = g_byte_array_sized_new(slen);
    const char *p = s, *end = s + slen;
    while (p < end) {
        gunichar cp = g_utf8_get_char_validated(p, end - p);
        guint8 b;
        if (*p == '\0') {
            b = 0;
            p++;
        } else if (cp == (gunichar)-1 || cp == (gunichar)-2) {
            g_byte_array_free(bytes, TRUE);
            JS_FreeCString(ctx, s);
            return ns_throw_dom_exception(ctx, "InvalidCharacterError", 5,
                "String contains an invalid character");
        } else if (cp > 0xFF) {
            g_byte_array_free(bytes, TRUE);
            JS_FreeCString(ctx, s);
            return ns_throw_dom_exception(ctx, "InvalidCharacterError", 5,
                "String contains an invalid character");
        } else {
            b = (guint8)cp;
            p = g_utf8_next_char(p);
        }
        g_byte_array_append(bytes, &b, 1);
    }
    JS_FreeCString(ctx, s);
    gchar *b64 = g_base64_encode(bytes->data, bytes->len);
    g_byte_array_free(bytes, TRUE);
    JSValue r = JS_NewString(ctx, b64);
    g_free(b64);
    return r;
}

static JSValue
ns_window_atob(JSContext *ctx, JSValueConst this_val,
               int argc, JSValueConst *argv)
{
    (void)this_val;
    if (argc < 1) return JS_NewString(ctx, "");
    size_t slen = 0;
    const char *s = JS_ToCStringLen(ctx, &slen, argv[0]);
    if (!s) return JS_NewString(ctx, "");
    GString *clean = g_string_sized_new(slen + 4);
    for (size_t i = 0; i < slen; i++) {
        unsigned char c = (unsigned char)s[i];
        if (c == ' ' || c == '\t' || c == '\n' || c == '\r' || c == '\f') continue;
        g_string_append_c(clean, (char)c);
    }
    if (clean->len % 4 == 0) {
        if (clean->len >= 2 &&
            clean->str[clean->len - 1] == '=' &&
            clean->str[clean->len - 2] == '=')
            g_string_truncate(clean, clean->len - 2);
        else if (clean->len >= 1 && clean->str[clean->len - 1] == '=')
            g_string_truncate(clean, clean->len - 1);
    }
    if (clean->len % 4 == 1) {
        g_string_free(clean, TRUE);
        JS_FreeCString(ctx, s);
        return ns_throw_dom_exception(ctx, "InvalidCharacterError", 5,
            "The string to be decoded is not correctly encoded");
    }
    for (gsize i = 0; i < clean->len; i++) {
        unsigned char c = (unsigned char)clean->str[i];
        gboolean ok = (c >= 'A' && c <= 'Z') || (c >= 'a' && c <= 'z') ||
                      (c >= '0' && c <= '9') || c == '+' || c == '/';
        if (!ok) {
            g_string_free(clean, TRUE);
            JS_FreeCString(ctx, s);
            return ns_throw_dom_exception(ctx, "InvalidCharacterError", 5,
                "The string to be decoded is not correctly encoded");
        }
    }
    while (clean->len % 4 != 0)
        g_string_append_c(clean, '=');
    gsize out_len = 0;
    guchar *out = g_base64_decode(clean->str, &out_len);
    g_string_free(clean, TRUE);
    JS_FreeCString(ctx, s);
    if (!out) return JS_NewStringLen(ctx, "", 0);
    GByteArray *utf8 = g_byte_array_sized_new(out_len + out_len / 2 + 1);
    for (gsize i = 0; i < out_len; i++) {
        guint8 b = out[i];
        if (b < 0x80) {
            g_byte_array_append(utf8, &b, 1);
        } else {
            guint8 two[2] = { (guint8)(0xC0 | (b >> 6)),
                              (guint8)(0x80 | (b & 0x3F)) };
            g_byte_array_append(utf8, two, 2);
        }
    }
    g_free(out);
    JSValue r = JS_NewStringLen(ctx, (const char *)utf8->data, utf8->len);
    g_byte_array_free(utf8, TRUE);
    return r;
}

static JSValue
ns_url_get_searchParams_object(JSContext *ctx, const char *search);

static JSValue
ns_url_get_searchParams_value(JSContext *ctx, JSValueConst init);

static JSValue
ns_window_url_ctor(JSContext *ctx, JSValueConst this_val,
                   int argc, JSValueConst *argv);

static JSValue
ns_url_parts_to_js(JSContext *ctx, const char *href)
{
    g_autoptr(ns_url_parts) parts = ns_url_parts_new(href);
    if (!parts) return JS_NULL;
    JSValue o = JS_NewObject(ctx);
    JS_SetPropertyStr(ctx, o, "href",     JS_NewString(ctx, parts->href));
    JS_SetPropertyStr(ctx, o, "protocol", JS_NewString(ctx, parts->protocol));
    JS_SetPropertyStr(ctx, o, "host",     JS_NewString(ctx, parts->host));
    JS_SetPropertyStr(ctx, o, "hostname", JS_NewString(ctx, parts->hostname));
    JS_SetPropertyStr(ctx, o, "port",     JS_NewString(ctx, parts->port));
    JS_SetPropertyStr(ctx, o, "origin",   JS_NewString(ctx, parts->origin));
    JS_SetPropertyStr(ctx, o, "pathname", JS_NewString(ctx, parts->pathname));
    JS_SetPropertyStr(ctx, o, "search",   JS_NewString(ctx, parts->search));
    JS_SetPropertyStr(ctx, o, "hash",     JS_NewString(ctx, parts->hash));
    JS_SetPropertyStr(ctx, o, "username", JS_NewString(ctx, parts->username));
    JS_SetPropertyStr(ctx, o, "password", JS_NewString(ctx, parts->password));
    return o;
}

static JSValue
ns_window_url_parts_internal(JSContext *ctx, JSValueConst this_val,
                             int argc, JSValueConst *argv)
{
    (void)this_val;
    if (argc < 1) return JS_NULL;
    const char *href = JS_ToCString(ctx, argv[0]);
    if (!href) return JS_NULL;
    JSValue o = ns_url_parts_to_js(ctx, href);
    JS_FreeCString(ctx, href);
    return o;
}

static JSValue
ns_window_url_set_internal(JSContext *ctx, JSValueConst this_val,
                           int argc, JSValueConst *argv)
{
    (void)this_val;
    if (argc < 3) return JS_NULL;
    const char *href = JS_ToCString(ctx, argv[0]);
    const char *comp = JS_ToCString(ctx, argv[1]);
    size_t val_len = 0;
    const char *val  = JS_ToCStringLen(ctx, &val_len, argv[2]);
    JSValue o = JS_NULL;
    if (href && comp && val) {
        char *next = ns_url_set_component_len(href, comp, val, val_len);
        if (next) {
            o = ns_url_parts_to_js(ctx, next);
            g_free(next);
        }
    }
    if (href) JS_FreeCString(ctx, href);
    if (comp) JS_FreeCString(ctx, comp);
    if (val)  JS_FreeCString(ctx, val);
    return o;
}

static JSValue
ns_window_url_can_parse(JSContext *ctx, JSValueConst this_val,
                        int argc, JSValueConst *argv)
{
    if (argc < 1)
        return JS_ThrowTypeError(ctx, "URL.canParse: 1 argument required");
    JSValue tmp = ns_window_url_ctor(ctx, this_val, argc, argv);
    if (JS_IsException(tmp)) {
        JS_FreeValue(ctx, JS_GetException(ctx));
        return JS_FALSE;
    }
    JS_FreeValue(ctx, tmp);
    return JS_TRUE;
}

static JSValue
ns_window_url_parse_static(JSContext *ctx, JSValueConst this_val,
                           int argc, JSValueConst *argv)
{
    if (argc < 1)
        return JS_ThrowTypeError(ctx, "URL.parse: 1 argument required");
    JSValue tmp = ns_window_url_ctor(ctx, this_val, argc, argv);
    if (JS_IsException(tmp)) {
        JS_FreeValue(ctx, JS_GetException(ctx));
        return JS_NULL;
    }
    return tmp;
}

static void
ns_url_install_interface(JSContext *ctx)
{
    static const char *src =
        "(function(){"
        " try { new URL('http://e/'); } catch(e) {}"
        " try { Object.defineProperty(globalThis, 'URL', { enumerable: false }); } catch(e) {}"
        " try { Object.defineProperty(URL, 'prototype', { writable: false }); } catch(e) {}"
        "})()";
    JSValue r = JS_Eval(ctx, src, strlen(src), "<url-iface>", JS_EVAL_TYPE_GLOBAL);
    if (JS_IsException(r)) JS_FreeValue(ctx, JS_GetException(ctx));
    JS_FreeValue(ctx, r);
}

static void
ns_usp_install_interface(JSContext *ctx)
{
    static const char *src =
        "(function(){"
        " try { new URLSearchParams(''); } catch(e) {}"
        " try { Object.defineProperty(globalThis, 'URLSearchParams', { enumerable: false }); } catch(e) {}"
        " try { Object.defineProperty(URLSearchParams, 'prototype', { writable: false }); } catch(e) {}"
        "})()";
    JSValue r = JS_Eval(ctx, src, strlen(src), "<usp-iface>", JS_EVAL_TYPE_GLOBAL);
    if (JS_IsException(r)) JS_FreeValue(ctx, JS_GetException(ctx));
    JS_FreeValue(ctx, r);
}

static JSValue
ns_window_url_ctor(JSContext *ctx, JSValueConst this_val,
                   int argc, JSValueConst *argv)
{
    (void)this_val;
    if (argc < 1) return JS_ThrowTypeError(ctx, "URL: requires a url string");
    size_t raw_len = 0;
    const char *raw = JS_ToCStringLen(ctx, &raw_len, argv[0]);
    if (!raw) return JS_ThrowTypeError(ctx, "URL: invalid url argument");
    char *resolved = NULL;
    if (argc >= 2 && !JS_IsUndefined(argv[1]) && !JS_IsNull(argv[1])) {
        const char *base = JS_ToCString(ctx, argv[1]);
        if (base) {
            resolved = ns_url_resolve_len(base, raw, raw_len);
            JS_FreeCString(ctx, base);
        }
        if (!resolved) {
            JS_FreeCString(ctx, raw);
            return JS_ThrowTypeError(ctx, "URL: invalid url");
        }
    }
    if (!resolved) {
        resolved = ns_url_resolve_len(NULL, raw, raw_len);
        if (!resolved) {
            JS_FreeCString(ctx, raw);
            return JS_ThrowTypeError(ctx,
                "URL: invalid or relative URL requires a base");
        }
    }
    JS_FreeCString(ctx, raw);
    ns_url_parts *parts = ns_url_parts_new(resolved);
    JSValue obj = JS_NewObject(ctx);
    if (parts) {
        JS_SetPropertyStr(ctx, obj, "href",     JS_NewString(ctx, parts->href));
        JS_SetPropertyStr(ctx, obj, "protocol", JS_NewString(ctx, parts->protocol));
        JS_SetPropertyStr(ctx, obj, "host",     JS_NewString(ctx, parts->host));
        JS_SetPropertyStr(ctx, obj, "hostname", JS_NewString(ctx, parts->hostname));
        JS_SetPropertyStr(ctx, obj, "port",     JS_NewString(ctx, parts->port));
        JS_SetPropertyStr(ctx, obj, "origin",   JS_NewString(ctx, parts->origin));
        JS_SetPropertyStr(ctx, obj, "pathname",
                          JS_NewString(ctx, parts->pathname));
        JS_SetPropertyStr(ctx, obj, "search",   JS_NewString(ctx, parts->search));
        JS_SetPropertyStr(ctx, obj, "hash",     JS_NewString(ctx, parts->hash));
        JS_SetPropertyStr(ctx, obj, "username", JS_NewString(ctx, parts->username));
        JS_SetPropertyStr(ctx, obj, "password", JS_NewString(ctx, parts->password));
        const char *q = *parts->search ? parts->search + 1 : "";
        JS_SetPropertyStr(ctx, obj, "searchParams",
                          ns_url_get_searchParams_object(ctx, q));
        ns_url_parts_free(parts);
    } else {
        JS_SetPropertyStr(ctx, obj, "href",     JS_NewString(ctx, resolved));
        JS_SetPropertyStr(ctx, obj, "protocol", JS_NewString(ctx, ""));
        JS_SetPropertyStr(ctx, obj, "host",     JS_NewString(ctx, ""));
        JS_SetPropertyStr(ctx, obj, "hostname", JS_NewString(ctx, ""));
        JS_SetPropertyStr(ctx, obj, "port",     JS_NewString(ctx, ""));
        JS_SetPropertyStr(ctx, obj, "origin",   JS_NewString(ctx, "null"));
        JS_SetPropertyStr(ctx, obj, "pathname", JS_NewString(ctx, "/"));
        JS_SetPropertyStr(ctx, obj, "search",   JS_NewString(ctx, ""));
        JS_SetPropertyStr(ctx, obj, "hash",     JS_NewString(ctx, ""));
        JS_SetPropertyStr(ctx, obj, "username", JS_NewString(ctx, ""));
        JS_SetPropertyStr(ctx, obj, "password", JS_NewString(ctx, ""));
        JS_SetPropertyStr(ctx, obj, "searchParams",
                          ns_url_get_searchParams_object(ctx, ""));
    }
    g_free(resolved);
    ns_js *jsx = js_from_ctx(ctx);
    if (jsx && !jsx->url_helper_set) {
        static const char *helper_src =
            "(function(u){"
            " var URLp = URL.prototype;"
            " if (!URLp.__ndReady) {"
            "   function nm(fn, n){ try { Object.defineProperty(fn, 'name',"
            "     { value: n, configurable: true }); } catch(e) {} return fn; }"
            "   function gettr(name){ return function(){ return this.__nd[name]; }; }"
            "   function setComp(comp){ return function(v){"
            "       var p = __ndUrlSet(this.__nd.href, comp, String(v));"
            "       if (p) { this.__nd = p; this.__ndSync(); } }; }"
            "   function accessor(name, setter){"
            "     Object.defineProperty(URLp, name, { configurable: true,"
            "       enumerable: true, get: nm(gettr(name), 'get ' + name),"
            "       set: setter ? nm(setter, 'set ' + name) : undefined }); }"
            "   accessor('href', function(v){"
            "     var p = __ndUrlParts(String(v));"
            "     if (!p) throw new TypeError('Invalid URL');"
            "     this.__nd = p; this.__ndSync(); });"
            "   accessor('origin', undefined);"
            "   ['protocol','username','password','host','hostname','port',"
            "    'pathname','search','hash'].forEach(function(n){"
            "       accessor(n, setComp(n)); });"
            "   Object.defineProperty(URLp, 'searchParams', { configurable: true,"
            "     enumerable: true, get: nm(function(){"
            "       if (!this.__nd) throw new TypeError('Illegal invocation');"
            "       return this.__ndSP; }, 'get searchParams') });"
            "   function method(name, fn){ Object.defineProperty(URLp, name,"
            "     { configurable: true, enumerable: true, writable: true,"
            "       value: nm(fn, name) }); }"
            "   method('toString', function(){ return this.__nd.href; });"
            "   method('toJSON',   function(){ return this.__nd.href; });"
            "   Object.defineProperty(URLp, '__ndSync', { configurable: true,"
            "     writable: true, value: function(){"
            "       try { var sp = new URLSearchParams(this.__nd.search.replace(/^\\?/, ''));"
            "             if (this.__ndSP) { this.__ndSP._p = sp._p; }"
            "             else { sp._owner = this;"
            "               Object.defineProperty(this, '__ndSP', { value: sp,"
            "                 configurable: true, writable: true }); } } catch(e) {} } });"
            "   Object.defineProperty(URLp, '_setSearchRaw', { configurable: true,"
            "     writable: true, value: function(v){"
            "       var p = __ndUrlSet(this.__nd.href, 'search', String(v));"
            "       if (p) { this.__nd = p; this.__ndSync(); } } });"
            "   try { Object.defineProperty(URLp, Symbol.toStringTag,"
            "     { value: 'URL', configurable: true }); } catch(e) {}"
            "   Object.defineProperty(URLp, '__ndReady', { value: true });"
            " }"
            " var nd = {"
            "   href: u.href, origin: u.origin,"
            "   protocol: u.protocol, username: u.username, password: u.password,"
            "   host: u.host, hostname: u.hostname, port: u.port,"
            "   pathname: (u.pathname == null ? '' : u.pathname), search: u.search || '', hash: u.hash || ''"
            " };"
            " var inst = Object.create(URLp);"
            " Object.defineProperty(inst, '__nd', { value: nd, configurable: true,"
            "   writable: true });"
            " inst.__ndSync();"
            " return inst;"
            "})";
        JSValue h = JS_Eval(ctx, helper_src, strlen(helper_src),
                            "<url-helper>", JS_EVAL_TYPE_GLOBAL);
        if (!JS_IsException(h)) {
            jsx->url_helper = h;
            jsx->url_helper_set = 1;
        } else {
            JS_FreeValue(ctx, JS_GetException(ctx));
            JS_FreeValue(ctx, h);
        }
    }
    if (jsx && jsx->url_helper_set) {
        JSValueConst args[1] = { obj };
        JSValue r = JS_Call(ctx, jsx->url_helper, JS_UNDEFINED, 1, args);
        if (JS_IsException(r)) {
            JS_FreeValue(ctx, JS_GetException(ctx));
            JS_FreeValue(ctx, r);
        } else {
            JS_FreeValue(ctx, obj);
            return r;
        }
    }
    return obj;
}

static JSValue
ns_url_get_searchParams_value(JSContext *ctx, JSValueConst init)
{
    ns_js *jsx = js_from_ctx(ctx);
    if (jsx && !jsx->search_params_helper_set) {
        static const char *helper_src =
            "(function(init){"
            " var USPp = URLSearchParams.prototype;"
            " if (!USPp.__ndReady) {"
            "   function nm(fn,n){ try { Object.defineProperty(fn,'name',"
            "     { value:n, configurable:true }); } catch(e){} return fn; }"
            "   function fenc(s){ return encodeURIComponent(String(s))"
            "     .replace(/[!~'()]/g,function(c){return '%'+c.charCodeAt(0).toString(16).toUpperCase();})"
            "     .replace(/%20/g,'+'); }"
            "   function meth(name, fn){ Object.defineProperty(USPp, name,"
            "     { configurable:true, enumerable:true, writable:true, value:nm(fn,name) }); }"
            "   function req(n,c){ if (c < n) throw new TypeError(n+' arguments required'); }"
            "   Object.defineProperty(USPp,'__notify',{configurable:true,writable:true,"
            "     value:function(){ if (this._owner && this._owner._setSearchRaw) {"
            "       var s=this.toString(); this._owner._setSearchRaw(s?'?'+s:''); } }});"
            "   meth('toString', function(){ return this._p.map(function(p){return fenc(p[0])+'='+fenc(p[1]);}).join('&'); });"
            "   meth('get', function(k){ req(1,arguments.length); k=String(k); for (var i=0;i<this._p.length;i++) if(this._p[i][0]===k) return this._p[i][1]; return null; });"
            "   meth('getAll', function(k){ req(1,arguments.length); k=String(k); var r=[]; for (var i=0;i<this._p.length;i++) if(this._p[i][0]===k) r.push(this._p[i][1]); return r; });"
            "   meth('has', function(k){ req(1,arguments.length); k=String(k); var hv=arguments.length>1&&arguments[1]!==undefined; var vv=hv?String(arguments[1]):null; for (var i=0;i<this._p.length;i++) if(this._p[i][0]===k&&(!hv||this._p[i][1]===vv)) return true; return false; });"
            "   meth('set', function(k,v){ req(2,arguments.length); k=String(k); v=String(v); var found=false; var out=[]; for (var i=0;i<this._p.length;i++){ if(this._p[i][0]===k){ if(!found){out.push([k,v]);found=true;} } else out.push(this._p[i]); } if(!found) out.push([k,v]); this._p=out; this.__notify(); });"
            "   meth('append', function(k,v){ req(2,arguments.length); this._p.push([String(k),String(v)]); this.__notify(); });"
            "   meth('delete', function(k){ req(1,arguments.length); k=String(k); var hv=arguments.length>1&&arguments[1]!==undefined; var vv=hv?String(arguments[1]):null; this._p=this._p.filter(function(p){return !(p[0]===k&&(!hv||p[1]===vv));}); this.__notify(); });"
            "   meth('sort', function(){ this._p.sort(function(a,b){return a[0]<b[0]?-1:a[0]>b[0]?1:0;}); this.__notify(); });"
            "   meth('forEach', function(cb){ req(1,arguments.length); var th=arguments[1]; for (var i=0;i<this._p.length;i++) cb.call(th,this._p[i][1],this._p[i][0],this); });"
            "   meth('keys', function*(){ for (var i=0;i<this._p.length;i++) yield this._p[i][0]; });"
            "   meth('values', function*(){ for (var i=0;i<this._p.length;i++) yield this._p[i][1]; });"
            "   meth('entries', function*(){ for (var i=0;i<this._p.length;i++) yield [this._p[i][0],this._p[i][1]]; });"
            "   Object.defineProperty(USPp, Symbol.iterator, { configurable:true, writable:true, value:USPp.entries });"
            "   Object.defineProperty(USPp,'size',{ configurable:true, enumerable:true, get:nm(function(){ return this._p.length; },'get size') });"
            "   try { Object.defineProperty(USPp,Symbol.toStringTag,{ value:'URLSearchParams', configurable:true }); } catch(e){}"
            "   Object.defineProperty(USPp,'__ndReady',{ value:true });"
            " }"
            " var pairs=[];"
            " function usv(s){s=String(s);var o='',i;for(i=0;i<s.length;i++){var c=s.charCodeAt(i);if(c>=0xD800&&c<=0xDBFF){var d=i+1<s.length?s.charCodeAt(i+1):0;if(d>=0xDC00&&d<=0xDFFF){o+=s[i]+s[i+1];i++;}else o+='\\uFFFD';}else if(c>=0xDC00&&c<=0xDFFF){o+='\\uFFFD';}else{o+=s[i];}}return o;}"
            " function add(k,v){pairs.push([usv(k),usv(v)]);}"
            " function pdecode(s){"
            "   s=String(s).replace(/\\+/g,' ');"
            "   var out=[];"
            "   for (var i=0;i<s.length;){"
            "     if (s.charCodeAt(i)===37 && i+2<s.length && /^[0-9a-fA-F]{2}$/.test(s.substr(i+1,2))){"
            "       out.push(parseInt(s.substr(i+1,2),16)); i+=3; continue;"
            "     }"
            "     var cp=s.codePointAt(i); i+=cp>65535?2:1;"
            "     if (cp<128) out.push(cp);"
            "     else if (cp<2048) out.push(192|(cp>>6),128|(cp&63));"
            "     else if (cp<65536) out.push(224|(cp>>12),128|((cp>>6)&63),128|(cp&63));"
            "     else out.push(240|(cp>>18),128|((cp>>12)&63),128|((cp>>6)&63),128|(cp&63));"
            "   }"
            "   return new TextDecoder('utf-8').decode(new Uint8Array(out));"
            " }"
            " function parse(q){"
            "   if (q && q[0]==='?') q=q.slice(1);"
            "   if (!q) return;"
            "   var parts=String(q).split('&');"
            "   for (var i=0;i<parts.length;i++){"
            "     if (!parts[i]) continue;"
            "     var eq=parts[i].indexOf('=');"
            "     var k=eq<0?parts[i]:parts[i].slice(0,eq);"
            "     var v=eq<0?'':parts[i].slice(eq+1);"
            "     add(pdecode(k),pdecode(v));"
            "   }"
            " }"
            " if (init == null) {"
            " } else if (typeof init === 'string') {"
            "   parse(init);"
            " } else if (typeof init === 'object' && typeof Symbol !== 'undefined' && typeof init[Symbol.iterator] === 'function') {"
            "   var it=init[Symbol.iterator](), step;"
            "   while(!(step=it.next()).done){"
            "     var p=step.value;"
            "     if (p == null || typeof p[Symbol.iterator] !== 'function')"
            "       throw new TypeError('Query pair must be iterable');"
            "     var pa=[]; var pit=p[Symbol.iterator]();"
            "     for (var ps;!(ps=pit.next()).done;) pa.push(ps.value);"
            "     if (pa.length !== 2) throw new TypeError('Each query pair must be an iterable [name, value] tuple');"
            "     add(pa[0],pa[1]);"
            "   }"
            " } else if (typeof init === 'object') {"
            "   var ks=Object.keys(init);"
            "   var rec=new Map();"
            "   for (var oi=0;oi<ks.length;oi++) rec.set(usv(ks[oi]),usv(init[ks[oi]]));"
            "   rec.forEach(function(v,k){pairs.push([k,v]);});"
            " } else {"
            "   parse(String(init));"
            " }"
            " var o = Object.create(URLSearchParams.prototype);"
            " Object.defineProperty(o,'_p',{value:pairs,configurable:true,writable:true});"
            " Object.defineProperty(o,'_owner',{value:null,configurable:true,writable:true});"
            " return o;"
            "})";
        JSValue h = JS_Eval(ctx, helper_src, strlen(helper_src),
                            "<usp-helper>", JS_EVAL_TYPE_GLOBAL);
        if (!JS_IsException(h)) {
            jsx->search_params_helper = h;
            jsx->search_params_helper_set = 1;
        } else {
            JS_FreeValue(ctx, JS_GetException(ctx));
            JS_FreeValue(ctx, h);
        }
    }
    if (!jsx || !jsx->search_params_helper_set) return JS_NewObject(ctx);
    JSValueConst args[1] = { init };
    return JS_Call(ctx, jsx->search_params_helper, JS_UNDEFINED, 1, args);
}

static JSValue
ns_url_get_searchParams_object(JSContext *ctx, const char *search)
{
    JSValue arg = JS_NewString(ctx, search ? search : "");
    JSValue obj = ns_url_get_searchParams_value(ctx, arg);
    JS_FreeValue(ctx, arg);
    return obj;
}

static JSValue
ns_window_document_fragment_ctor(JSContext *ctx, JSValueConst this_val,
                                 int argc, JSValueConst *argv)
{
    (void)this_val; (void)argc; (void)argv;
    if (!js_from_ctx(ctx)) return JS_NULL;
    ns_node *frag = ns_node_new_document();
    frag->flags |= NS_NODE_FRAGMENT;
    g_hash_table_add(js_from_ctx(ctx)->orphan_nodes, frag);
    return ns_make_element(ctx, frag);
}

static JSValue
ns_window_text_ctor(JSContext *ctx, JSValueConst this_val,
                    int argc, JSValueConst *argv)
{
    (void)this_val;
    ns_js *js = js_from_ctx(ctx);
    if (!js) return JS_NULL;
    char *dup;
    if (argc >= 1 && !JS_IsUndefined(argv[0])) {
        const char *s = JS_ToCString(ctx, argv[0]);
        if (!s) return JS_EXCEPTION;
        dup = g_strdup(s);
        JS_FreeCString(ctx, s);
    } else {
        dup = g_strdup("");
    }
    ns_node *n = ns_node_new_text(dup);
    g_hash_table_add(js->orphan_nodes, n);
    return ns_make_element(ctx, n);
}

static JSValue
ns_window_comment_ctor(JSContext *ctx, JSValueConst this_val,
                       int argc, JSValueConst *argv)
{
    (void)this_val;
    ns_js *js = js_from_ctx(ctx);
    if (!js) return JS_NULL;
    char *dup;
    if (argc >= 1 && !JS_IsUndefined(argv[0])) {
        const char *s = JS_ToCString(ctx, argv[0]);
        if (!s) return JS_EXCEPTION;
        dup = g_strdup(s);
        JS_FreeCString(ctx, s);
    } else {
        dup = g_strdup("");
    }
    ns_node *n = ns_node_new_comment(dup);
    g_hash_table_add(js->orphan_nodes, n);
    return ns_make_element(ctx, n);
}




























static JSValue
ns_window_image_ctor(JSContext *ctx, JSValueConst this_val,
                     int argc, JSValueConst *argv)
{
    (void)this_val;
    if (!js_from_ctx(ctx)) return JS_NULL;
    ns_node *el = ns_node_new_element(g_strdup("img"));
    if (argc >= 1) {
        int32_t w = 0;
        if (JS_ToInt32(ctx, &w, argv[0]) == 0 && w > 0) {
            char buf[16];
            g_snprintf(buf, sizeof buf, "%d", w);
            ns_element_set_attr(el, "width", buf);
        }
    }
    if (argc >= 2) {
        int32_t h = 0;
        if (JS_ToInt32(ctx, &h, argv[1]) == 0 && h > 0) {
            char buf[16];
            g_snprintf(buf, sizeof buf, "%d", h);
            ns_element_set_attr(el, "height", buf);
        }
    }
    g_hash_table_add(js_from_ctx(ctx)->orphan_nodes, el);
    return ns_make_element(ctx, el);
}

static JSValue
ns_window_audio_ctor(JSContext *ctx, JSValueConst this_val,
                     int argc, JSValueConst *argv)
{
    (void)this_val;
    if (!js_from_ctx(ctx)) return JS_NULL;
    ns_node *el = ns_node_new_element(g_strdup("audio"));
    if (argc >= 1) {
        const char *s = JS_ToCString(ctx, argv[0]);
        if (s) { ns_element_set_attr(el, "src", s); JS_FreeCString(ctx, s); }
    }
    g_hash_table_add(js_from_ctx(ctx)->orphan_nodes, el);
    return ns_make_element(ctx, el);
}

static JSValue
ns_window_option_ctor(JSContext *ctx, JSValueConst this_val,
                      int argc, JSValueConst *argv)
{
    (void)this_val;
    if (!js_from_ctx(ctx)) return JS_NULL;
    ns_node *el = ns_node_new_element(g_strdup("option"));
    if (argc >= 1) {
        const char *t = JS_ToCString(ctx, argv[0]);
        if (t) {
            ns_node_append_child(el, ns_node_new_text(g_strdup(t)));
            JS_FreeCString(ctx, t);
        }
    }
    if (argc >= 2) {
        const char *v = JS_ToCString(ctx, argv[1]);
        if (v) { ns_element_set_attr(el, "value", v); JS_FreeCString(ctx, v); }
    }
    if (argc >= 3 && JS_ToBool(ctx, argv[2]))
        ns_element_set_attr(el, "defaultSelected", "");
    if (argc >= 4 && JS_ToBool(ctx, argv[3]))
        ns_element_set_attr(el, "selected", "");
    g_hash_table_add(js_from_ctx(ctx)->orphan_nodes, el);
    return ns_make_element(ctx, el);
}

static JSValue
ns_window_usp_ctor(JSContext *ctx, JSValueConst this_val,
                   int argc, JSValueConst *argv)
{
    (void)this_val;
    if (argc >= 1) return ns_url_get_searchParams_value(ctx, argv[0]);
    return ns_url_get_searchParams_value(ctx, JS_UNDEFINED);
}

