static char *
ns_media_resolve_src(JSContext *ctx, ns_node *node)
{
    if (!node) return NULL;
    const char *src = ns_element_get_attr(node, "src");
    if (!src || !*src) {
        for (const ns_node *c = node->first_child; c; c = c->next_sibling) {
            if (ns_node_is_element_named(c, "source")) {
                const char *ss = ns_element_get_attr(c, "src");
                if (ss && *ss) { src = ss; break; }
            }
        }
    }
    if (!src || !*src) return NULL;
    ns_js *js = js_from_ctx(ctx);
    return (js && js->current_url) ? ns_url_resolve(js->current_url, src)
                                   : g_strdup(src);
}

static void
ns_media_blob_updated_node(ns_js *js, ns_node *node, const char *url,
                           int depth)
{
    if (!node || depth >= 512) return;
    if (ns_node_is_element_named(node, "audio")) {
        char *src = ns_media_resolve_src(js->ctx, node);
        gboolean matches = src && strcmp(src, url) == 0;
        g_free(src);
        if (matches) {
            JSValue element = ns_make_element(js->ctx, node);
            JSValue opened = JS_GetPropertyStr(js->ctx, element,
                                               "_nd_audio_opened");
            if (JS_ToBool(js->ctx, opened)) {
                JSValue token = JS_GetPropertyStr(js->ctx, element,
                                                  "_nd_audio_token");
                if (JS_IsString(token)) {
                    const char *value = JS_ToCString(js->ctx, token);
                    if (value) {
                        ns_js_emit_audio(js, "reload %s %s", value, url);
                        JS_FreeCString(js->ctx, value);
                    }
                }
                JS_FreeValue(js->ctx, token);
            }
            JS_FreeValue(js->ctx, opened);
            JS_FreeValue(js->ctx, element);
        }
    }
    for (ns_node *child = node->first_child; child;
         child = child->next_sibling)
        ns_media_blob_updated_node(js, child, url, depth + 1);
}

static void
ns_media_blob_updated(ns_js *js, const char *url)
{
    if (!js || !js->current_doc || !url) return;
    ns_media_blob_updated_node(js, js->current_doc, url, 0);
}

static char *
ns_media_token(JSContext *ctx, ns_node *node)
{
    ns_js *js = js_from_ctx(ctx);
    if (!js || !node) return NULL;
    JSValue v = ns_make_element(ctx, node);
    JSValue tv = JS_GetPropertyStr(ctx, v, "_nd_audio_token");
    char *token = NULL;
    if (JS_IsString(tv)) {
        const char *s = JS_ToCString(ctx, tv);
        token = g_strdup(s);
        JS_FreeCString(ctx, s);
    } else {
        token = g_strdup_printf("a%u", ++js->next_audio_token);
        JS_SetPropertyStr(ctx, v, "_nd_audio_token", JS_NewString(ctx, token));
    }
    JS_FreeValue(ctx, tv);
    JS_FreeValue(ctx, v);
    return token;
}

static JSValue
ns_media_play(JSContext *ctx, JSValueConst this_val,
              int argc, JSValueConst *argv)
{
    (void)argc; (void)argv;
    JS_SetPropertyStr(ctx, this_val, "_nd_playing", JS_TRUE);
    JS_SetPropertyStr(ctx, this_val, "_nd_ended", JS_FALSE);
    ns_node *el = ns_unwrap_element_mut(this_val);
    ns_js *js = js_from_ctx(ctx);
    if (el && js) {
        ns_js_dispatch_event(js, el, "play", NULL);
        if (js->media_play_cb)
            js->media_play_cb(el, TRUE, js->media_play_user_data);
        char *url = ns_media_resolve_src(ctx, el);
        gboolean audio_element = ns_node_is_element_named(el, "audio");
        if (url && js->audio_cb && audio_element) {
            char *token = ns_media_token(ctx, el);
            JSValue opened = JS_GetPropertyStr(ctx, this_val, "_nd_audio_opened");
            gboolean already = JS_ToBool(ctx, opened);
            JS_FreeValue(ctx, opened);
            if (!already) {
                ns_js_emit_audio(js, "open %s %s", token, url);
                JS_SetPropertyStr(ctx, this_val, "_nd_audio_opened", JS_TRUE);
            }
            ns_js_emit_audio(js, "play %s", token);
            g_free(token);
        } else {
            ns_js_dispatch_event(js, el, "playing", NULL);
        }
        g_free(url);
    }
    return ns_returns_resolved_undefined(ctx, this_val, 0, NULL);
}

static JSValue
ns_media_get_current_time(JSContext *ctx, JSValueConst this_val)
{
    JSValue v = JS_GetPropertyStr(ctx, this_val, "_nd_pos");
    if (JS_IsNumber(v)) return v;
    JS_FreeValue(ctx, v);
    return JS_NewFloat64(ctx, 0.0);
}

static JSValue
ns_media_get_duration(JSContext *ctx, JSValueConst this_val)
{
    JSValue v = JS_GetPropertyStr(ctx, this_val, "_nd_duration");
    if (JS_IsNumber(v)) return v;
    JS_FreeValue(ctx, v);
    return JS_NewFloat64(ctx, NAN);
}

static JSValue
ns_time_ranges_edge(JSContext *ctx, JSValueConst this_val,
                    int argc, JSValueConst *argv, int magic,
                    JSValue *func_data)
{
    (void)this_val;
    double dur = 0;
    int32_t len = 0;
    JS_ToFloat64(ctx, &dur, func_data[0]);
    JS_ToInt32(ctx, &len, func_data[1]);
    int32_t idx = 0;
    if (argc >= 1) JS_ToInt32(ctx, &idx, argv[0]);
    if (idx < 0 || idx >= len)
        return JS_ThrowRangeError(ctx, "index out of TimeRanges bounds");
    return JS_NewFloat64(ctx, magic == 0 ? 0.0 : dur);
}

static void
ns_obj_adopt_global_proto(JSContext *ctx, JSValueConst obj, const char *iface)
{
    JSValue global = JS_GetGlobalObject(ctx);
    JSValue ctor = JS_GetPropertyStr(ctx, global, iface);
    if (JS_IsObject(ctor)) {
        JSValue proto = JS_GetPropertyStr(ctx, ctor, "prototype");
        if (JS_IsObject(proto)) JS_SetPrototype(ctx, obj, proto);
        JS_FreeValue(ctx, proto);
    }
    JS_FreeValue(ctx, ctor);
    JS_FreeValue(ctx, global);
}

static JSValue
ns_media_time_ranges_for(JSContext *ctx, double dur)
{
    int len = dur > 0 ? 1 : 0;
    JSValue obj = JS_NewObject(ctx);
    ns_obj_adopt_global_proto(ctx, obj, "TimeRanges");
    JS_SetPropertyStr(ctx, obj, "length", JS_NewInt32(ctx, len));
    JSValue data[2] = { JS_NewFloat64(ctx, dur), JS_NewInt32(ctx, len) };
    JS_SetPropertyStr(ctx, obj, "start",
        JS_NewCFunctionData(ctx, ns_time_ranges_edge, 1, 0, 2, data));
    JS_SetPropertyStr(ctx, obj, "end",
        JS_NewCFunctionData(ctx, ns_time_ranges_edge, 1, 1, 2, data));
    JS_FreeValue(ctx, data[0]);
    JS_FreeValue(ctx, data[1]);
    return obj;
}

static double
ns_media_prop_number(JSContext *ctx, JSValueConst this_val, const char *name)
{
    double out = 0;
    JSValue v = JS_GetPropertyStr(ctx, this_val, name);
    if (JS_IsNumber(v)) JS_ToFloat64(ctx, &out, v);
    JS_FreeValue(ctx, v);
    if (isnan(out) || out <= 0) out = 0;
    return out;
}

static JSValue
ns_media_get_seekable_ranges(JSContext *ctx, JSValueConst this_val)
{
    return ns_media_time_ranges_for(ctx,
        ns_media_prop_number(ctx, this_val, "_nd_duration"));
}

static JSValue
ns_media_get_buffered_ranges(JSContext *ctx, JSValueConst this_val)
{
    double end = ns_media_prop_number(ctx, this_val, "_nd_buffered");
    return ns_media_time_ranges_for(ctx, end);
}

static JSValue
ns_media_get_played_ranges(JSContext *ctx, JSValueConst this_val)
{
    (void)this_val;
    return ns_media_time_ranges_for(ctx, 0);
}

static JSValue
ns_media_get_ended(JSContext *ctx, JSValueConst this_val)
{
    JSValue v = JS_GetPropertyStr(ctx, this_val, "_nd_ended");
    gboolean ended = JS_ToBool(ctx, v);
    JS_FreeValue(ctx, v);
    return JS_NewBool(ctx, ended);
}

static gboolean
ns_node_is_media_element(const ns_node *n)
{
    return n && n->kind == NS_NODE_ELEMENT && n->name &&
           (g_ascii_strcasecmp(n->name, "video") == 0 ||
            g_ascii_strcasecmp(n->name, "audio") == 0);
}

static JSValue
ns_media_get_error(JSContext *ctx, JSValueConst this_val)
{
    JSValue v = JS_GetPropertyStr(ctx, this_val, "_nd_error");
    if (JS_IsObject(v)) return v;
    JS_FreeValue(ctx, v);
    const ns_node *n = ns_unwrap_element(this_val);
    return ns_node_is_media_element(n) ? JS_NULL : JS_UNDEFINED;
}

static JSValue
ns_media_get_playbackRate(JSContext *ctx, JSValueConst this_val)
{
    JSValue v = JS_GetPropertyStr(ctx, this_val, "_nd_rate");
    if (JS_IsNumber(v)) return v;
    JS_FreeValue(ctx, v);
    return JS_NewFloat64(ctx, 1.0);
}

static JSValue
ns_media_set_playbackRate(JSContext *ctx, JSValueConst this_val,
                          JSValueConst val)
{
    double rate = 1.0;
    if (JS_ToFloat64(ctx, &rate, val)) return JS_EXCEPTION;
    if (isnan(rate)) rate = 1.0;
    JS_SetPropertyStr(ctx, this_val, "_nd_rate", JS_NewFloat64(ctx, rate));
    ns_js *js = js_from_ctx(ctx);
    ns_node *el = ns_unwrap_element_mut(this_val);
    if (js && el && ns_node_is_media_element(el))
        ns_js_dispatch_event(js, el, "ratechange", NULL);
    return JS_UNDEFINED;
}

static JSValue
ns_media_get_defaultPlaybackRate(JSContext *ctx, JSValueConst this_val)
{
    JSValue v = JS_GetPropertyStr(ctx, this_val, "_nd_default_rate");
    if (JS_IsNumber(v)) return v;
    JS_FreeValue(ctx, v);
    return JS_NewFloat64(ctx, 1.0);
}

static JSValue
ns_media_set_defaultPlaybackRate(JSContext *ctx, JSValueConst this_val,
                                 JSValueConst val)
{
    double rate = 1.0;
    if (JS_ToFloat64(ctx, &rate, val)) return JS_EXCEPTION;
    if (isnan(rate)) rate = 1.0;
    JS_SetPropertyStr(ctx, this_val, "_nd_default_rate",
                      JS_NewFloat64(ctx, rate));
    return JS_UNDEFINED;
}

static JSValue
ns_media_load(JSContext *ctx, JSValueConst this_val,
              int argc, JSValueConst *argv)
{
    (void)argc; (void)argv;
    ns_node *el = ns_unwrap_element_mut(this_val);
    if (!ns_node_is_media_element(el)) return JS_UNDEFINED;
    JS_SetPropertyStr(ctx, this_val, "_nd_pos", JS_NewFloat64(ctx, 0.0));
    JS_SetPropertyStr(ctx, this_val, "_nd_duration", JS_UNDEFINED);
    JS_SetPropertyStr(ctx, this_val, "_nd_buffered", JS_UNDEFINED);
    JS_SetPropertyStr(ctx, this_val, "_nd_ended", JS_FALSE);
    JS_SetPropertyStr(ctx, this_val, "_nd_playing", JS_FALSE);
    JS_SetPropertyStr(ctx, this_val, "_nd_error", JS_UNDEFINED);
    JS_SetPropertyStr(ctx, this_val, "_nd_readyState", JS_NewInt32(ctx, 0));
    JS_SetPropertyStr(ctx, this_val, "_nd_networkState", JS_NewInt32(ctx, 2));
    JS_DefinePropertyValueStr(ctx, this_val, "readyState",
                              JS_NewInt32(ctx, 0), JS_PROP_C_W_E);
    JS_DefinePropertyValueStr(ctx, this_val, "videoWidth",
                              JS_NewInt32(ctx, 0), JS_PROP_C_W_E);
    JS_DefinePropertyValueStr(ctx, this_val, "videoHeight",
                              JS_NewInt32(ctx, 0), JS_PROP_C_W_E);
    ns_js *js = js_from_ctx(ctx);
    if (js && el) {
        ns_js_dispatch_event(js, el, "emptied", NULL);
        ns_js_dispatch_event(js, el, "loadstart", NULL);
    }
    return JS_UNDEFINED;
}

static JSValue
ns_media_get_volume(JSContext *ctx, JSValueConst this_val)
{
    JSValue v = JS_GetPropertyStr(ctx, this_val, "_nd_volume");
    if (JS_IsNumber(v)) return v;
    JS_FreeValue(ctx, v);
    return JS_NewFloat64(ctx, 1.0);
}

static JSValue
ns_media_set_volume(JSContext *ctx, JSValueConst this_val, JSValueConst val)
{
    double vol = 1.0;
    if (JS_ToFloat64(ctx, &vol, val)) return JS_EXCEPTION;
    if (isnan(vol)) vol = 1.0;
    if (vol < 0) vol = 0;
    if (vol > 1) vol = 1;
    JS_SetPropertyStr(ctx, this_val, "_nd_volume", JS_NewFloat64(ctx, vol));
    ns_js *js = js_from_ctx(ctx);
    ns_node *el = ns_unwrap_element_mut(this_val);
    if (js && el) {
        if (js->audio_cb) {
            JSValue tv = JS_GetPropertyStr(ctx, this_val, "_nd_audio_token");
            if (JS_IsString(tv)) {
                const char *token = JS_ToCString(ctx, tv);
                if (token) {
                    ns_js_emit_audio(js, "volume %s %.3f", token, vol);
                    JS_FreeCString(ctx, token);
                }
            }
            JS_FreeValue(ctx, tv);
        }
        ns_js_dispatch_event(js, el, "volumechange", NULL);
    }
    return JS_UNDEFINED;
}

static JSValue
ns_media_get_muted(JSContext *ctx, JSValueConst this_val)
{
    JSValue v = JS_GetPropertyStr(ctx, this_val, "_nd_muted");
    if (!JS_IsUndefined(v)) {
        gboolean m = JS_ToBool(ctx, v) ? TRUE : FALSE;
        JS_FreeValue(ctx, v);
        return JS_NewBool(ctx, m);
    }
    JS_FreeValue(ctx, v);
    const ns_node *n = ns_unwrap_element(this_val);
    return JS_NewBool(ctx, n && ns_element_get_attr(n, "muted") != NULL);
}

static JSValue
ns_media_set_muted(JSContext *ctx, JSValueConst this_val, JSValueConst val)
{
    gboolean m = JS_ToBool(ctx, val) ? TRUE : FALSE;
    JS_SetPropertyStr(ctx, this_val, "_nd_muted", JS_NewBool(ctx, m));
    ns_js *js = js_from_ctx(ctx);
    ns_node *el = ns_unwrap_element_mut(this_val);
    if (js && el) {
        if (js->audio_cb) {
            JSValue tv = JS_GetPropertyStr(ctx, this_val, "_nd_audio_token");
            if (JS_IsString(tv)) {
                const char *token = JS_ToCString(ctx, tv);
                if (token) {
                    double vol = 0.0;
                    if (!m) {
                        JSValue vv = JS_GetPropertyStr(ctx, this_val, "_nd_volume");
                        if (JS_IsNumber(vv)) JS_ToFloat64(ctx, &vol, vv);
                        else vol = 1.0;
                        JS_FreeValue(ctx, vv);
                    }
                    ns_js_emit_audio(js, "volume %s %.3f", token, vol);
                    JS_FreeCString(ctx, token);
                }
            }
            JS_FreeValue(ctx, tv);
        }
        ns_js_dispatch_event(js, el, "volumechange", NULL);
    }
    return JS_UNDEFINED;
}

static JSValue
ns_media_set_current_time(JSContext *ctx, JSValueConst this_val,
                          JSValueConst val)
{
    double t = 0.0;
    if (JS_ToFloat64(ctx, &t, val)) return JS_EXCEPTION;
    if (isnan(t) || t < 0.0) t = 0.0;
    ns_node *el = ns_unwrap_element_mut(this_val);
    ns_js *js = js_from_ctx(ctx);
    if (!el || !js) return JS_UNDEFINED;
    gboolean handled = js->media_seek_cb &&
        js->media_seek_cb(el, t, js->media_seek_user_data);
    if (!handled && js->audio_cb) {
        JSValue tv = JS_GetPropertyStr(ctx, this_val, "_nd_audio_token");
        if (JS_IsString(tv)) {
            const char *token = JS_ToCString(ctx, tv);
            if (token) {
                ns_js_emit_audio(js, "seek %s %.3f", token, t);
                handled = TRUE;
                JS_FreeCString(ctx, token);
            }
        }
        JS_FreeValue(ctx, tv);
    }
    JS_SetPropertyStr(ctx, this_val, "_nd_pos", JS_NewFloat64(ctx, t));
    if (handled) {
        JS_SetPropertyStr(ctx, this_val, "_nd_ended", JS_FALSE);
        ns_js_dispatch_event(js, el, "seeking", NULL);
        ns_js_dispatch_event(js, el, "timeupdate", NULL);
        ns_js_dispatch_event(js, el, "seeked", NULL);
    }
    return JS_UNDEFINED;
}

static JSValue
ns_media_fast_seek(JSContext *ctx, JSValueConst this_val,
                   int argc, JSValueConst *argv)
{
    if (argc < 1) return JS_UNDEFINED;
    return ns_media_set_current_time(ctx, this_val, argv[0]);
}

static JSValue
ns_media_get_video_playback_quality(JSContext *ctx, JSValueConst this_val,
                                    int argc, JSValueConst *argv)
{
    (void)argc;
    (void)argv;
    double pos = 0;
    JSValue pv = JS_GetPropertyStr(ctx, this_val, "_nd_pos");
    if (JS_IsNumber(pv)) JS_ToFloat64(ctx, &pos, pv);
    JS_FreeValue(ctx, pv);
    JSValue q = JS_NewObject(ctx);
    JS_SetPropertyStr(ctx, q, "creationTime",
                      JS_NewFloat64(ctx, ns_perf_now_ms(js_from_ctx(ctx))));
    JS_SetPropertyStr(ctx, q, "totalVideoFrames",
                      JS_NewInt32(ctx, (int)(pos * 30.0)));
    JS_SetPropertyStr(ctx, q, "droppedVideoFrames", JS_NewInt32(ctx, 0));
    JS_SetPropertyStr(ctx, q, "corruptedVideoFrames", JS_NewInt32(ctx, 0));
    return q;
}

static JSValue
ns_media_get_srcObject(JSContext *ctx, JSValueConst this_val)
{
    JSValue v = JS_GetPropertyStr(ctx, this_val, "_nd_srcObject");
    if (JS_IsUndefined(v)) { JS_FreeValue(ctx, v); return JS_NULL; }
    return v;
}

static JSValue
ns_media_set_srcObject(JSContext *ctx, JSValueConst this_val, JSValueConst val)
{
    JS_SetPropertyStr(ctx, this_val, "_nd_srcObject", JS_DupValue(ctx, val));
    ns_node *el = ns_unwrap_element_mut(this_val);
    ns_js *js = js_from_ctx(ctx);
    gboolean is_cam = FALSE;
    if (JS_IsObject(val)) {
        JSValue m = JS_GetPropertyStr(ctx, val, "_nd_camera");
        is_cam = JS_ToBool(ctx, m);
        JS_FreeValue(ctx, m);
    }
    if (el) {
        ns_element_set_attr(el, NS_MEDIA_STREAM_ATTR, is_cam ? "camera" : "");
        if (js) js->mutated = TRUE;
    }
    if (el && js && is_cam)
        ns_js_dispatch_event(js, el, "loadedmetadata", NULL);
    return JS_UNDEFINED;
}

static JSValue
ns_media_pause(JSContext *ctx, JSValueConst this_val,
               int argc, JSValueConst *argv)
{
    (void)argc; (void)argv;
    JS_SetPropertyStr(ctx, this_val, "_nd_playing", JS_FALSE);
    ns_node *el = ns_unwrap_element_mut(this_val);
    ns_js *js = js_from_ctx(ctx);
    if (el && js) {
        JSValue tv = JS_GetPropertyStr(ctx, this_val, "_nd_audio_token");
        if (JS_IsString(tv)) {
            const char *token = JS_ToCString(ctx, tv);
            if (token) { ns_js_emit_audio(js, "pause %s", token); JS_FreeCString(ctx, token); }
        }
        JS_FreeValue(ctx, tv);
        ns_js_dispatch_event(js, el, "pause", NULL);
        if (js->media_play_cb)
            js->media_play_cb(el, FALSE, js->media_play_user_data);
    }
    return JS_UNDEFINED;
}

static JSValue
ns_media_request_video_frame_callback(JSContext *ctx, JSValueConst this_val,
                                      int argc, JSValueConst *argv)
{
    (void)this_val;
    if (!js_from_ctx(ctx) || argc < 1 || !JS_IsFunction(ctx, argv[0]))
        return JS_NewInt32(ctx, 0);
    ns_js *js = js_from_ctx(ctx);
    if (!js->raf_pending)
        js->raf_pending = g_array_new(FALSE, FALSE, sizeof(ns_raf_entry));
    ns_raf_entry e = {
        .id = ++js->next_raf_id,
        .cb = JS_DupValue(ctx, argv[0]),
        .video_frame = TRUE,
        .frame = js->raf_frame_ctx
    };
    g_array_append_val(js->raf_pending, e);
    ns_raf_schedule_tick(js);
    return JS_NewInt32(ctx, e.id);
}

static JSValue
ns_window_invoke_action(JSContext *ctx, const char *action)
{
    ns_js *js = js_from_ctx(ctx);
    if (js && js->window_action_cb)
        js->window_action_cb(action, js->window_action_user_data);
    return JS_UNDEFINED;
}

static JSValue
ns_window_print(JSContext *ctx, JSValueConst this_val,
                int argc, JSValueConst *argv)
{
    (void)this_val; (void)argc; (void)argv;
    return ns_window_invoke_action(ctx, "print");
}

static JSValue
ns_window_stop(JSContext *ctx, JSValueConst this_val,
               int argc, JSValueConst *argv)
{
    (void)this_val; (void)argc; (void)argv;
    return ns_window_invoke_action(ctx, "stop");
}

static void
ns_read_scroll_xy(JSContext *ctx, int argc, JSValueConst *argv,
                  double *out_x, double *out_y)
{
    double x = 0, y = 0;
    if (argc >= 1 && JS_IsObject(argv[0]) && !JS_IsNumber(argv[0])) {
        JSValue lv = JS_GetPropertyStr(ctx, argv[0], "left");
        JSValue tv = JS_GetPropertyStr(ctx, argv[0], "top");
        JS_ToFloat64(ctx, &x, lv);
        JS_ToFloat64(ctx, &y, tv);
        JS_FreeValue(ctx, lv);
        JS_FreeValue(ctx, tv);
    } else {
        if (argc >= 1) JS_ToFloat64(ctx, &x, argv[0]);
        if (argc >= 2) JS_ToFloat64(ctx, &y, argv[1]);
    }
    *out_x = x;
    *out_y = y;
}

static JSValue
ns_window_scroll_to(JSContext *ctx, JSValueConst this_val,
                    int argc, JSValueConst *argv)
{
    (void)this_val;
    double x = 0, y = 0;
    ns_read_scroll_xy(ctx, argc, argv, &x, &y);
    ns_js_note_viewport_scroll(js_from_ctx(ctx), x, y);
    return JS_UNDEFINED;
}

static JSValue
ns_window_scroll_by(JSContext *ctx, JSValueConst this_val,
                    int argc, JSValueConst *argv)
{
    double dx = 0, dy = 0;
    ns_read_scroll_xy(ctx, argc, argv, &dx, &dy);
    JSValue cur_x = JS_GetPropertyStr(ctx, this_val, "scrollX");
    JSValue cur_y = JS_GetPropertyStr(ctx, this_val, "scrollY");
    double x = 0, y = 0;
    JS_ToFloat64(ctx, &x, cur_x);
    JS_ToFloat64(ctx, &y, cur_y);
    JS_FreeValue(ctx, cur_x);
    JS_FreeValue(ctx, cur_y);
    ns_js_note_viewport_scroll(js_from_ctx(ctx), x + dx, y + dy);
    return JS_UNDEFINED;
}

static JSValue
ns_window_scroll_by_vertical(JSContext *ctx, JSValueConst this_val, double dy)
{
    JSValue dyv = JS_NewFloat64(ctx, dy);
    JSValueConst args[2] = { JS_NewInt32(ctx, 0), dyv };
    JSValue r = ns_window_scroll_by(ctx, this_val, 2, args);
    JS_FreeValue(ctx, args[0]);
    JS_FreeValue(ctx, dyv);
    return r;
}

static JSValue
ns_window_scroll_by_lines(JSContext *ctx, JSValueConst this_val,
                          int argc, JSValueConst *argv)
{
    int lines = 0;
    if (argc >= 1) JS_ToInt32(ctx, &lines, argv[0]);
    return ns_window_scroll_by_vertical(ctx, this_val, lines * 16.0);
}

static JSValue
ns_window_scroll_by_pages(JSContext *ctx, JSValueConst this_val,
                          int argc, JSValueConst *argv)
{
    int pages = 0;
    if (argc >= 1) JS_ToInt32(ctx, &pages, argv[0]);
    double vh = 800;
    JSValue ih = JS_GetPropertyStr(ctx, this_val, "innerHeight");
    JS_ToFloat64(ctx, &vh, ih);
    JS_FreeValue(ctx, ih);
    return ns_window_scroll_by_vertical(ctx, this_val, pages * vh);
}

static JSValue
ns_window_focus(JSContext *ctx, JSValueConst this_val,
                int argc, JSValueConst *argv)
{
    (void)this_val; (void)argc; (void)argv;
    return ns_window_invoke_action(ctx, "focus");
}

static JSValue
ns_element_scroll_common(JSContext *ctx, JSValueConst this_val,
                         int argc, JSValueConst *argv, gboolean relative)
{
    double x = 0, y = 0;
    gboolean has_x = FALSE, has_y = FALSE;
    if (argc >= 1 && JS_IsObject(argv[0]) && !JS_IsNumber(argv[0])) {
        JSValue lv = JS_GetPropertyStr(ctx, argv[0], "left");
        JSValue tv = JS_GetPropertyStr(ctx, argv[0], "top");
        if (!JS_IsUndefined(lv)) has_x = JS_ToFloat64(ctx, &x, lv) == 0;
        if (!JS_IsUndefined(tv)) has_y = JS_ToFloat64(ctx, &y, tv) == 0;
        JS_FreeValue(ctx, lv);
        JS_FreeValue(ctx, tv);
    } else {
        if (argc >= 1 && !JS_IsUndefined(argv[0]))
            has_x = JS_ToFloat64(ctx, &x, argv[0]) == 0;
        if (argc >= 2 && !JS_IsUndefined(argv[1]))
            has_y = JS_ToFloat64(ctx, &y, argv[1]) == 0;
    }
    if (relative) {
        JSValue cur_x = ns_element_get_scrollLeft(ctx, this_val);
        JSValue cur_y = ns_element_get_scrollTop(ctx, this_val);
        double cx = 0, cy = 0;
        JS_ToFloat64(ctx, &cx, cur_x);
        JS_ToFloat64(ctx, &cy, cur_y);
        JS_FreeValue(ctx, cur_x);
        JS_FreeValue(ctx, cur_y);
        x += cx;
        y += cy;
    }
    if (has_x) {
        JSValue v = JS_NewFloat64(ctx, x);
        ns_element_set_scrollLeft(ctx, this_val, v);
        JS_FreeValue(ctx, v);
    }
    if (has_y) {
        JSValue v = JS_NewFloat64(ctx, y);
        ns_element_set_scrollTop(ctx, this_val, v);
        JS_FreeValue(ctx, v);
    }
    return JS_UNDEFINED;
}

static JSValue
ns_element_scroll_to(JSContext *ctx, JSValueConst this_val,
                     int argc, JSValueConst *argv)
{
    return ns_element_scroll_common(ctx, this_val, argc, argv, FALSE);
}

static JSValue
ns_element_scroll_by(JSContext *ctx, JSValueConst this_val,
                     int argc, JSValueConst *argv)
{
    return ns_element_scroll_common(ctx, this_val, argc, argv, TRUE);
}

static ns_node *
ns_iframe_document_node(const ns_node *iframe)
{
    if (!iframe) return NULL;
    for (ns_node *c = iframe->first_child; c; c = c->next_sibling)
        if (c->kind == NS_NODE_DOCUMENT) return c;
    return NULL;
}

static ns_node *
ns_iframe_content_root(const ns_node *iframe)
{
    if (!iframe) return NULL;
    for (ns_node *c = iframe->first_child; c; c = c->next_sibling) {
        if (c->kind == NS_NODE_DOCUMENT) {
            for (ns_node *e = c->first_child; e; e = e->next_sibling)
                if (e->kind == NS_NODE_ELEMENT) return e;
            return NULL;
        }
        if (c->kind == NS_NODE_ELEMENT) return c;
    }
    return NULL;
}

static ns_node *
ns_iframe_ensure_content_root(ns_node *iframe)
{
    ns_node *root = ns_iframe_content_root(iframe);
    if (root) return root;
    if (!iframe) return NULL;
    root = ns_node_new_element(g_strdup("html"));
    ns_node_append_child(root, ns_node_new_element(g_strdup("head")));
    ns_node_append_child(root, ns_node_new_element(g_strdup("body")));
    ns_node *doc = ns_node_new_document();
    ns_node_append_child(doc, root);
    ns_node_append_child(iframe, doc);
    return root;
}

static JSValue
ns_js_doc_enter(JSContext *ctx, JSValueConst this_val, int argc, JSValueConst *argv)
{
    (void)this_val;
    ns_js *js = js_from_ctx(ctx);
    if (!js) return JS_UNDEFINED;
    if (!js->doc_stack)
        js->doc_stack = g_array_new(FALSE, FALSE, sizeof(gpointer));
    gpointer prev = js->current_doc;
    g_array_append_val(js->doc_stack, prev);
    ns_node *root = (argc >= 1) ? ns_unwrap_element_mut(argv[0]) : NULL;
    if (root) js->current_doc = root;
    return JS_UNDEFINED;
}

static JSValue
ns_js_doc_exit(JSContext *ctx, JSValueConst this_val, int argc, JSValueConst *argv)
{
    (void)this_val; (void)argc; (void)argv;
    ns_js *js = js_from_ctx(ctx);
    if (js && js->doc_stack && js->doc_stack->len > 0) {
        js->current_doc = g_array_index(js->doc_stack, gpointer,
                                        js->doc_stack->len - 1);
        g_array_set_size(js->doc_stack, js->doc_stack->len - 1);
    }
    return JS_UNDEFINED;
}

static const char ns_iframe_scope_bootstrap[] =
    "(function(realWin, iframeDoc, initialURL, sandbox){"
    "  var url = initialURL || 'about:blank';"
    "  var hashL = [], popL = [], onhash = null, onpop = null, state = null;"
    "  var msgL = [], onmsg = null;"
    "  var win;"
    "  function mk(u, b){ try { return new realWin.URL(u, b || url); } catch(e){ return null; } }"
    "  function fire(list, on, ev){"
    "    var c = list.slice();"
    "    for (var i=0;i<c.length;i++){ try { c[i].call(win, ev); } catch(e){} }"
    "    if (on) { try { on.call(win, ev); } catch(e){} }"
    "  }"
    "  function evt(type, props){"
    "    var e = null;"
    "    try { if (realWin.Event) { e = new realWin.Event(type); } } catch(x){}"
    "    if (!e) e = { type: type };"
    "    if (props) for (var k in props) { try { e[k] = props[k]; } catch(x){} }"
    "    return e;"
    "  }"
    "  function fireHash(o, n){ fire(hashL, onhash, evt('hashchange', {oldURL:o, newURL:n})); }"
    "  function firePop(){ fire(popL, onpop, evt('popstate', {state:state})); }"
    "  function sameDoc(a, b){ var ua=mk(a), ub=mk(b);"
    "    return !!ua && !!ub && ua.origin===ub.origin && ua.pathname===ub.pathname && ua.search===ub.search; }"
    "  var loc = {};"
    "  ['protocol','host','hostname','port','pathname','search','origin'].forEach(function(p){"
    "    Object.defineProperty(loc, p, { configurable:true, enumerable:true,"
    "      get: function(){ var u=mk(url); return u ? u[p] : ''; } }); });"
    "  Object.defineProperty(loc, 'href', { configurable:true, enumerable:true,"
    "    get: function(){ return url; },"
    "    set: function(v){ var u=mk(v);"
    "      if(!u) throw new DOMException('location: invalid URL','SyntaxError');"
    "      var o=url; url=u.href;"
    "      if (o!==url && sameDoc(o,url)) fireHash(o,url); } });"
    "  Object.defineProperty(loc, 'hash', { configurable:true, enumerable:true,"
    "    get: function(){ var u=mk(url); return u ? u.hash : ''; },"
    "    set: function(v){ var u=mk(url); if(!u) return; u.hash=v; var o=url; url=u.href;"
    "      if (o!==url) fireHash(o,url); } });"
    "  loc.assign = function(v){ this.href = v; };"
    "  loc.replace = function(v){ this.href = v; };"
    "  loc.reload = function(){};"
    "  loc.toString = function(){ return url; };"
    "  var hist = {"
    "    get state(){ return state; }, get length(){ return 1; }, scrollRestoration:'auto',"
    "    pushState: function(s,t,u){ state=s; if(u!=null){ var n=mk(u); if(n) url=n.href; } },"
    "    replaceState: function(s,t,u){ state=s; if(u!=null){ var n=mk(u); if(n) url=n.href; } },"
    "    back: function(){ firePop(); }, forward: function(){ firePop(); }, go: function(){ firePop(); }"
    "  };"
    "  var ov = {"
    "    location: loc, history: hist, document: iframeDoc,"
    "    fetch: function(input, init){"
    "      var req = input;"
    "      try { if (typeof input === 'string') { var u = mk(input); if (u) req = u.href; } } catch(e){}"
    "      return realWin.fetch.call(win, req, init); },"
    "    get onhashchange(){ return onhash; }, set onhashchange(v){ onhash=v; },"
    "    get onpopstate(){ return onpop; }, set onpopstate(v){ onpop=v; },"
    "    get onmessage(){ return onmsg; }, set onmessage(v){ onmsg=v; },"
    "    __nsDeliverMessage: function(ev){ fire(msgL, onmsg, ev); },"
    "    postMessage: realWin.__nsPostMessageThis,"
    "    addEventListener: function(type, fn, o){"
    "      if (type==='hashchange'){ hashL.push(fn); return; }"
    "      if (type==='popstate'){ popL.push(fn); return; }"
    "      if (type==='message'){ msgL.push(fn); return; }"
    "      return realWin.addEventListener(type, fn, o); },"
    "    removeEventListener: function(type, fn, o){"
    "      var i; if (type==='hashchange'){ i=hashL.indexOf(fn); if(i>=0) hashL.splice(i,1); return; }"
    "      if (type==='popstate'){ i=popL.indexOf(fn); if(i>=0) popL.splice(i,1); return; }"
    "      if (type==='message'){ i=msgL.indexOf(fn); if(i>=0) msgL.splice(i,1); return; }"
    "      return realWin.removeEventListener(type, fn, o); },"
    "    dispatchEvent: function(ev){"
    "      if (ev && ev.type==='hashchange'){ fire(hashL, onhash, ev); return true; }"
    "      if (ev && ev.type==='popstate'){ fire(popL, onpop, ev); return true; }"
    "      if (ev && ev.type==='message'){ fire(msgL, onmsg, ev); return true; }"
    "      return realWin.dispatchEvent(ev); }"
    "  };"
    "  if (sandbox & 1) {"
    "    if (!(sandbox & 32)) {"
    "      ov.alert = function(){};"
    "      ov.confirm = function(){ return false; };"
    "      ov.prompt = function(){ return null; };"
    "      ov.print = function(){};"
    "    }"
    "    if (!(sandbox & 16)) { ov.open = function(){ return null; }; }"
    "  }"
    "  if ((sandbox & 8192) || ((sandbox & 1) && !(sandbox & 8))) {"
    "    var denyStore = function(){"
    "      try { return new realWin.DOMException('The operation is insecure.', 'SecurityError'); }"
    "      catch(e){ return new Error('SecurityError'); } };"
    "    Object.defineProperty(ov, 'localStorage', { configurable:true, get: function(){ throw denyStore(); } });"
    "    Object.defineProperty(ov, 'sessionStorage', { configurable:true, get: function(){ throw denyStore(); } });"
    "    Object.defineProperty(ov, 'indexedDB', { configurable:true, get: function(){ throw denyStore(); } });"
    "  }"
    "  function ovGet(p){"
    "    var d = Object.getOwnPropertyDescriptor(ov, p);"
    "    return d && d.get ? d.get.call(ov) : ov[p];"
    "  }"
    "  function ovSet(p, v){"
    "    var d = Object.getOwnPropertyDescriptor(ov, p);"
    "    if (d && d.set){ d.set.call(ov, v); return true; }"
    "    if (d && d.writable===false) return false;"
    "    ov[p] = v; return true;"
    "  }"
    "  win = new Proxy(realWin, {"
    "    get: function(t, p){"
    "      if (p==='window'||p==='self'||p==='globalThis'||p==='frames') return win;"
    "      if (p==='parent') return realWin;"
    "      if (p==='top') return realWin.top && typeof realWin.top === 'object' ? realWin.top : realWin;"
    "      if (Object.prototype.hasOwnProperty.call(ov, p)) return ovGet(p);"
    "      return Reflect.get(t, p, t); },"
    "    set: function(t, p, v){"
    "      if (p==='location'){ loc.href = v; return true; }"
    "      return ovSet(p, v); },"
    "    defineProperty: function(t, p, d){ try { Object.defineProperty(ov, p, d); return true; } catch(e){ return false; } },"
    "    getOwnPropertyDescriptor: function(t, p){"
    "      if (Object.prototype.hasOwnProperty.call(ov, p)) return Object.getOwnPropertyDescriptor(ov, p);"
    "      return Reflect.getOwnPropertyDescriptor(t, p); },"
    "    deleteProperty: function(t, p){ if (Object.prototype.hasOwnProperty.call(ov, p)) return delete ov[p]; return true; },"
    "    ownKeys: function(t){"
    "      var seen = Object.create(null), out = [];"
    "      Reflect.ownKeys(t).forEach(function(k){ seen[k]=1; out.push(k); });"
    "      Reflect.ownKeys(ov).forEach(function(k){ if(!seen[k]) out.push(k); });"
    "      return out; },"
    "    has: function(t, p){ return Object.prototype.hasOwnProperty.call(ov, p) || (p in t); }"
    "  });"
    "  return { window: win, location: loc, history: hist };"
    "})";

static JSValue
ns_iframe_make_scope(JSContext *ctx, JSValue iframe_doc, const char *initial_url,
                     unsigned sandbox)
{
    JSValue global = JS_GetGlobalObject(ctx);
    JSValue maker = JS_Eval(ctx, ns_iframe_scope_bootstrap,
                            strlen(ns_iframe_scope_bootstrap),
                            "<iframe-scope>", JS_EVAL_TYPE_GLOBAL);
    JSValue scope = JS_NULL;
    if (!JS_IsException(maker) && JS_IsFunction(ctx, maker)) {
        JSValue urlv = JS_NewString(ctx, initial_url ? initial_url : "about:blank");
        JSValue sbv = JS_NewInt32(ctx, (int32_t)sandbox);
        JSValueConst args[4] = { global, iframe_doc, urlv, sbv };
        scope = JS_Call(ctx, maker, JS_UNDEFINED, 4, args);
        if (JS_IsException(scope)) { JS_FreeValue(ctx, JS_GetException(ctx)); scope = JS_NULL; }
        JS_FreeValue(ctx, urlv);
    } else if (JS_IsException(maker)) {
        JS_FreeValue(ctx, JS_GetException(ctx));
    }
    JS_FreeValue(ctx, maker);
    JS_FreeValue(ctx, global);
    return scope;
}

