static JSContext *
ns_iframe_make_realm_context(ns_js *js, JSValueConst iframe_doc,
                             const char *initial_url, unsigned sandbox,
                             JSValue *out_window, JSValue *out_location,
                             JSValue *out_history)
{
    *out_window = JS_NULL;
    *out_location = JS_NULL;
    *out_history = JS_NULL;
    JSContext *fctx = JS_NewContext(js->rt);
    if (!fctx) return NULL;
    JS_SetContextOpaque(fctx, js);
    g_ptr_array_add(js->frame_ctxs, fctx);

    JSClassID dom_ids[6] = {
        ns_element_class_id, ns_style_class_id, ns_token_list_class_id,
        ns_live_class_id, ns_dataset_class_id, ns_storage_class_id,
    };
    for (gsize i = 0; i < G_N_ELEMENTS(dom_ids); i++) {
        if (!dom_ids[i]) continue;
        JSValue proto = JS_GetClassProto(js->ctx, dom_ids[i]);
        if (JS_IsObject(proto))
            JS_SetClassProto(fctx, dom_ids[i], JS_DupValue(fctx, proto));
        JS_FreeValue(js->ctx, proto);
    }

    JSValue fg = JS_GetGlobalObject(fctx);
    JSValue parent_global = JS_GetGlobalObject(js->ctx);
    JS_SetPrototype(fctx, fg, parent_global);

    JSValue maker = JS_Eval(fctx, ns_iframe_global_bootstrap,
                            strlen(ns_iframe_global_bootstrap),
                            "<iframe-global>", JS_EVAL_TYPE_GLOBAL);
    gboolean ok = FALSE;
    if (!JS_IsException(maker) && JS_IsFunction(fctx, maker)) {
        JSValue urlv = JS_NewString(fctx, initial_url ? initial_url : "about:blank");
        JSValue sbv = JS_NewInt32(fctx, (int32_t)sandbox);
        JSValueConst args[5] = { fg, parent_global, iframe_doc, urlv, sbv };
        JSValue res = JS_Call(fctx, maker, JS_UNDEFINED, 5, args);
        if (!JS_IsException(res) && JS_IsObject(res)) {
            *out_location = JS_GetPropertyStr(fctx, res, "location");
            *out_history  = JS_GetPropertyStr(fctx, res, "history");
            ok = TRUE;
        } else if (JS_IsException(res)) {
            JS_FreeValue(fctx, JS_GetException(fctx));
        }
        JS_FreeValue(fctx, res);
        JS_FreeValue(fctx, urlv);
    } else if (JS_IsException(maker)) {
        JS_FreeValue(fctx, JS_GetException(fctx));
    }
    JS_FreeValue(fctx, maker);
    JS_FreeValue(fctx, parent_global);

    if (!ok) {
        JS_FreeValue(fctx, fg);
        return NULL;
    }
    *out_window = fg;
    return fctx;
}

static void
ns_iframe_store_realm_window(ns_js *js, ns_node *iframe, JSValueConst window)
{
    if (!js || !js->frame_windows || !iframe || !JS_IsObject(window)) return;
    gpointer old = g_hash_table_lookup(js->frame_windows, iframe);
    if (old)
        JS_FreeValue(js->ctx, JS_MKPTR(JS_TAG_OBJECT, old));
    JSValue held = JS_DupValue(js->ctx, window);
    g_hash_table_insert(js->frame_windows, iframe, JS_VALUE_GET_PTR(held));
}

static JSValue
ns_iframe_lookup_realm_window(ns_js *js, ns_node *iframe)
{
    if (!js || !js->frame_windows || !iframe) return JS_NULL;
    gpointer p = g_hash_table_lookup(js->frame_windows, iframe);
    if (!p) return JS_NULL;
    return JS_DupValue(js->ctx, JS_MKPTR(JS_TAG_OBJECT, p));
}

static JSValue ns_document_createElement(JSContext *ctx, JSValueConst this_val,
                                         int argc, JSValueConst *argv);
static JSValue ns_document_createTextNode(JSContext *ctx, JSValueConst this_val,
                                          int argc, JSValueConst *argv);
static JSValue ns_document_ctor(JSContext *ctx, JSValueConst this_val,
                                int argc, JSValueConst *argv);
static JSValue ns_document_implementation(JSContext *ctx,
                                          JSValueConst this_val);

static void
ns_document_use_document_prototype(JSContext *ctx, JSValueConst obj)
{
    JSValue global = JS_GetGlobalObject(ctx);
    JSValue ctor = JS_GetPropertyStr(ctx, global, "Document");
    JSValue proto = JS_GetPropertyStr(ctx, ctor, "prototype");
    if (JS_IsObject(proto)) JS_SetPrototype(ctx, obj, proto);
    JS_FreeValue(ctx, proto);
    JS_FreeValue(ctx, ctor);
    JS_FreeValue(ctx, global);
}

static void
ns_document_use_xml_document_prototype(JSContext *ctx, JSValueConst obj)
{
    JSValue global = JS_GetGlobalObject(ctx);
    JSValue ctor = JS_GetPropertyStr(ctx, global, "XMLDocument");
    JSValue proto = JS_GetPropertyStr(ctx, ctor, "prototype");
    JSValue doc_ctor = JS_GetPropertyStr(ctx, global, "Document");
    JSValue doc_proto = JS_GetPropertyStr(ctx, doc_ctor, "prototype");
    if (JS_IsObject(proto) && JS_IsObject(doc_proto))
        JS_SetPrototype(ctx, proto, doc_proto);
    if (JS_IsObject(proto)) JS_SetPrototype(ctx, obj, proto);
    JS_FreeValue(ctx, doc_proto);
    JS_FreeValue(ctx, doc_ctor);
    JS_FreeValue(ctx, proto);
    JS_FreeValue(ctx, ctor);
    JS_FreeValue(ctx, global);
}

static JSValue
ns_document_implementation_getter_fn(JSContext *ctx, JSValueConst this_val,
                                     int argc, JSValueConst *argv)
{
    (void)argc; (void)argv;
    return ns_document_implementation(ctx, this_val);
}

static void
ns_document_define_implementation_getter(JSContext *ctx, JSValueConst obj)
{
    JSAtom atom = JS_NewAtom(ctx, "implementation");
    JSValue getter = JS_NewCFunction(ctx, ns_document_implementation_getter_fn,
                                     "get implementation", 0);
    JS_DefinePropertyGetSet(ctx, obj, atom, getter, JS_UNDEFINED,
                            JS_PROP_CONFIGURABLE);
    JS_FreeAtom(ctx, atom);
}

static JSValue
ns_iframe_build_content_document(JSContext *ctx, ns_node *iframe)
{
    if (!ns_iframe_ensure_content_root(iframe)) return JS_NULL;
    ns_node *doc = ns_iframe_document_node(iframe);
    if (!doc) return JS_NULL;
    const char *cs = iframe
        ? ns_element_get_attr(iframe, "data-nd-frame-charset") : NULL;
    const char *url = iframe
        ? ns_element_get_attr(iframe, "data-nd-frame-url") : NULL;
    JSValue cd = ns_make_realm_document(ctx, doc, url, cs, "text/html", FALSE, FALSE);
    if (JS_IsObject(cd))
        JS_SetPropertyStr(ctx, cd, "defaultView", JS_GetGlobalObject(ctx));
    return cd;
}

static JSValue
ns_element_get_contentDocument(JSContext *ctx, JSValueConst this_val)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n || (!ns_node_is_element_named(n, "iframe") &&
               !ns_node_is_element_named(n, "object"))) return JS_NULL;
    JSValue realm = JS_GetPropertyStr(ctx, this_val, "__ndRealmDoc");
    if (JS_IsObject(realm)) return realm;
    JS_FreeValue(ctx, realm);
    if (!ns_node_is_element_named(n, "iframe")) return JS_NULL;
    return ns_iframe_build_content_document(ctx, n);
}

static JSValue
ns_iframe_build_lite_window(JSContext *ctx, JSValueConst iframe_el,
                            ns_node *iframe)
{
    ns_js *js = js_from_ctx(ctx);
    if (!js) return JS_GetGlobalObject(ctx);
    JSValue doc = ns_element_get_contentDocument(ctx, iframe_el);
    if (!JS_IsObject(doc)) {
        JS_FreeValue(ctx, doc);
        return JS_GetGlobalObject(ctx);
    }
    const char *url = ns_element_get_attr(iframe, "data-nd-frame-url");
    JSValue fwin = JS_NULL, floc = JS_NULL, fhist = JS_NULL;
    JSContext *fctx = ns_iframe_make_realm_context(js, doc,
        url && *url ? url : "about:blank",
        ns_iframe_effective_sandbox(iframe), &fwin, &floc, &fhist);
    if (!fctx || !JS_IsObject(fwin)) {
        JS_FreeValue(ctx, doc);
        JS_FreeValue(ctx, fwin);
        JS_FreeValue(ctx, floc);
        JS_FreeValue(ctx, fhist);
        return JS_GetGlobalObject(ctx);
    }
    JS_FreeValue(ctx, floc);
    JS_FreeValue(ctx, fhist);
    JS_SetPropertyStr(ctx, doc, "defaultView", JS_DupValue(ctx, fwin));
    ns_iframe_store_realm_window(js, iframe, fwin);
    JS_SetPropertyStr(ctx, iframe_el, "__ndRealmWindow",
                      JS_DupValue(ctx, fwin));
    JS_SetPropertyStr(ctx, iframe_el, "__ndRealmDoc", doc);
    return fwin;
}

static JSValue
ns_element_get_contentWindow(JSContext *ctx, JSValueConst this_val)
{
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n || !ns_node_is_element_named(n, "iframe")) return JS_NULL;
    if (!ns_iframe_ensure_content_root(n)) return JS_NULL;
    JSValue realm = JS_GetPropertyStr(ctx, this_val, "__ndRealmWindow");
    if (JS_IsObject(realm)) return realm;
    JS_FreeValue(ctx, realm);
    ns_js *js = js_from_ctx(ctx);
    JSValue stored = ns_iframe_lookup_realm_window(js, n);
    if (JS_IsObject(stored)) return stored;
    JS_FreeValue(ctx, stored);
    return ns_iframe_build_lite_window(ctx, this_val, n);
}

static void
ns_collect_frames_walk(JSContext *ctx, const ns_node *n, JSValue arr,
                       uint32_t *i, int depth)
{
    if (!n || depth >= 256) return;
    for (const ns_node *c = n->first_child; c; c = c->next_sibling) {
        if (c->kind == NS_NODE_ELEMENT && c->name &&
            (g_ascii_strcasecmp(c->name, "iframe") == 0 ||
             g_ascii_strcasecmp(c->name, "frame") == 0)) {
            JSValue el = ns_make_element(ctx, c);
            JS_SetPropertyUint32(ctx, arr, (*i)++,
                                 ns_element_get_contentWindow(ctx, el));
            JS_FreeValue(ctx, el);
            continue;
        }
        ns_collect_frames_walk(ctx, c, arr, i, depth + 1);
    }
}

static JSValue
ns_window_get_frames(JSContext *ctx, JSValueConst this_val, int argc,
                     JSValueConst *argv)
{
    (void)this_val; (void)argc; (void)argv;
    return JS_GetGlobalObject(ctx);
}

static JSValue
ns_window_get_length(JSContext *ctx, JSValueConst this_val, int argc,
                     JSValueConst *argv)
{
    (void)this_val; (void)argc; (void)argv;
    ns_js *js = js_from_ctx(ctx);
    JSValue arr = JS_NewArray(ctx);
    uint32_t i = 0;
    if (js && js->current_doc)
        ns_collect_frames_walk(ctx, js->current_doc, arr, &i, 0);
    JSValue len = JS_GetPropertyStr(ctx, arr, "length");
    JS_FreeValue(ctx, arr);
    return len;
}

static JSValue
ns_element_getSVGDocument(JSContext *ctx, JSValueConst this_val,
                          int argc, JSValueConst *argv)
{
    (void)argc; (void)argv;
    ns_node *n = ns_unwrap_element_mut(this_val);
    if (!n || (!ns_node_is_element_named(n, "iframe") &&
               !ns_node_is_element_named(n, "object") &&
               !ns_node_is_element_named(n, "embed")))
        return JS_NULL;
    JSValue doc = ns_element_get_contentDocument(ctx, this_val);
    if (!JS_IsObject(doc)) return doc;
    JSValue root = JS_GetPropertyStr(ctx, doc, "documentElement");
    JSValue name = JS_IsObject(root) ? JS_GetPropertyStr(ctx, root, "localName")
                                     : JS_NULL;
    const char *nm = JS_ToCString(ctx, name);
    gboolean is_svg = nm && g_ascii_strcasecmp(nm, "svg") == 0;
    if (nm) JS_FreeCString(ctx, nm);
    JS_FreeValue(ctx, name);
    JS_FreeValue(ctx, root);
    if (is_svg) return doc;
    JS_FreeValue(ctx, doc);
    return JS_NULL;
}

static JSValue
ns_element_getNumberOfChars(JSContext *ctx, JSValueConst this_val,
                            int argc, JSValueConst *argv)
{
    (void)argc; (void)argv;
    const ns_node *n = ns_unwrap_element(this_val);
    if (!n) return JS_NewInt32(ctx, 0);
    char *t = ns_node_collect_text(n);
    glong len = t ? g_utf8_strlen(t, -1) : 0;
    g_free(t);
    return JS_NewInt32(ctx, (int)len);
}

