static JSValue
ns_document_get_lastModified(JSContext *ctx, JSValueConst this_val)
{
    (void)this_val;
    GDateTime *now = g_date_time_new_now_local();
    JSValue r;
    if (now) {
        char *s = g_date_time_format(now, "%m/%d/%Y %H:%M:%S");
        r = JS_NewString(ctx, s ? s : "");
        g_free(s);
        g_date_time_unref(now);
    } else {
        r = JS_NewString(ctx, "");
    }
    return r;
}

